const StatCard: React.FC<{ title: string; value: string; sub: string; icon: React.ReactNode }> = ({ title, value, sub, icon }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
    <div className="flex justify-between items-start mb-4">
      <div className="p-3 bg-slate-50 rounded-lg">{icon}</div>
      <span className="text-xs font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">+2.5%</span>
    </div>
    <h4 className="text-slate-500 text-sm font-medium">{title}</h4>
    <p className="text-2xl font-bold text-slate-800 mt-1">{value}</p>
    <p className="text-xs text-slate-400 mt-1">{sub}</p>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { Plus, Search, Filter, Edit2, Trash2, MoreVertical } from 'lucide-react';
import { Student, AcademicLevel, Career } from '../types';

interface StudentsModuleProps {
  students: Student[];
  careers: Career[];
  onAddStudent: (s: Omit<Student, 'id'>) => void;
  onDeleteStudent: (id: string) => void;
}

const StudentsModule: React.FC<StudentsModuleProps> = ({ students, careers, onAddStudent, onDeleteStudent }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [levelFilter, setLevelFilter] = useState<AcademicLevel | 'ALL'>('ALL');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [newStudent, setNewStudent] = useState<Omit<Student, 'id'>>({
    dni: '',
    firstName: '',
    lastName: '',
    level: AcademicLevel.INITIAL,
    careerIds: [],
    grade: '',
    enrollmentDate: new Date().toISOString().split('T')[0],
    status: 'ACTIVE'
  });

  const filteredStudents = students.filter(s => {
    const matchesSearch = `${s.firstName} ${s.lastName} ${s.dni}`.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesLevel = levelFilter === 'ALL' || s.level === levelFilter;
    return matchesSearch && matchesLevel;
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddStudent(newStudent);
    setIsModalOpen(false);
    // Reset form
    setNewStudent({
      dni: '',
      firstName: '',
      lastName: '',
      level: AcademicLevel.INITIAL,
      careerIds: [],
      grade: '',
      enrollmentDate: new Date().toISOString().split('T')[0],
      status: 'ACTIVE'
    });
  };

  const toggleCareer = (careerId: string) => {
    const current = newStudent.careerIds;
    if (current.includes(careerId)) {
      setNewStudent({...newStudent, careerIds: current.filter(id => id !== careerId)});
    } else {
      setNewStudent({...newStudent, careerIds: [...current, careerId]});
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
        <div className="flex gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar por nombre, apellido o DNI..." 
              className="pl-10 pr-4 py-2 w-full border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none"
            value={levelFilter}
            onChange={(e) => setLevelFilter(e.target.value as AcademicLevel | 'ALL')}
          >
            <option value="ALL">Todos los Niveles</option>
            {Object.values(AcademicLevel).map(l => (
              <option key={l} value={l}>{l}</option>
            ))}
          </select>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 font-medium hover:bg-blue-700 transition-colors w-full md:w-auto justify-center"
        >
          <Plus size={20} />
          Nuevo Alumno
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Alumno</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">DNI</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Nivel / Grado</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Estado</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredStudents.map((student) => (
              <tr key={student.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-medium">
                      {student.firstName[0]}{student.lastName[0]}
                    </div>
                    <div>
                      <p className="font-semibold text-slate-800">{student.firstName} {student.lastName}</p>
                      <p className="text-xs text-slate-400">Ingreso: {student.enrollmentDate}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 text-slate-600 font-medium">{student.dni}</td>
                <td className="px-6 py-4">
                  <span className={`text-xs px-2 py-1 rounded-full font-bold inline-block ${
                    student.level === AcademicLevel.INITIAL ? 'bg-pink-100 text-pink-700' :
                    student.level === AcademicLevel.PRIMARY ? 'bg-blue-100 text-blue-700' :
                    student.level === AcademicLevel.SECONDARY ? 'bg-amber-100 text-amber-700' :
                    'bg-emerald-100 text-emerald-700'
                  }`}>
                    {student.level}
                  </span>
                  <p className="text-xs text-slate-500 mt-1">
                    {student.level === AcademicLevel.TERTIARY 
                      ? `${student.careerIds.length} Carreras` 
                      : student.grade || 'Sin asignar'}
                  </p>
                </td>
                <td className="px-6 py-4">
                  <span className={`inline-block w-2 h-2 rounded-full mr-2 ${student.status === 'ACTIVE' ? 'bg-emerald-500' : 'bg-slate-300'}`}></span>
                  <span className="text-sm text-slate-600">{student.status === 'ACTIVE' ? 'Activo' : 'Inactivo'}</span>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><Edit2 size={16} /></button>
                    <button 
                      onClick={() => onDeleteStudent(student.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 transition-colors"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Add Student Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">Alta de Alumno</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">×</button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 overflow-y-auto space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Nombre</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={newStudent.firstName}
                    onChange={e => setNewStudent({...newStudent, firstName: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Apellido</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={newStudent.lastName}
                    onChange={e => setNewStudent({...newStudent, lastName: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">DNI</label>
                  <input 
                    required 
                    type="text" 
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={newStudent.dni}
                    onChange={e => setNewStudent({...newStudent, dni: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Nivel Académico</label>
                  <select 
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={newStudent.level}
                    onChange={e => setNewStudent({...newStudent, level: e.target.value as AcademicLevel, careerIds: [], grade: ''})}
                  >
                    {Object.values(AcademicLevel).map(l => (
                      <option key={l} value={l}>{l}</option>
                    ))}
                  </select>
                </div>
              </div>

              {newStudent.level !== AcademicLevel.TERTIARY ? (
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Grado / Año</label>
                  <input 
                    type="text" 
                    placeholder="Ej: 3ro Primaria"
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={newStudent.grade}
                    onChange={e => setNewStudent({...newStudent, grade: e.target.value})}
                  />
                </div>
              ) : (
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Inscripción a Carreras (Múltiple)</label>
                  <div className="grid grid-cols-1 gap-2 p-3 bg-slate-50 rounded-lg border border-slate-200">
                    {careers.map(career => (
                      <label key={career.id} className="flex items-center gap-2 cursor-pointer p-2 hover:bg-white rounded transition-colors">
                        <input 
                          type="checkbox" 
                          checked={newStudent.careerIds.includes(career.id)}
                          onChange={() => toggleCareer(career.id)}
                          className="w-4 h-4 text-blue-600 rounded"
                        />
                        <span className="text-sm text-slate-700">{career.name}</span>
                      </label>
                    ))}
                  </div>
                  <p className="text-xs text-slate-500 mt-1 italic">* Nota: En nivel terciario se cobrará una cuota por cada carrera inscripta.</p>
                </div>
              )}

              <div className="pt-4 flex gap-3">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-2 border border-slate-200 rounded-lg text-slate-600 font-medium hover:bg-slate-50">Cancelar</button>
                <button type="submit" className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700">Guardar Alumno</button>
              </div>
