import React, { useState } from 'react';
import { ClipboardList, Calendar, Info, Check, X } from 'lucide-react';
import { Student, Exam, Payment, Subject } from '../types';
import { validateExamRegistration } from '../utils';

interface ExamsModuleProps {
  students: Student[];
  exams: Exam[];
  subjects: Subject[];
  payments: Payment[];
}

const ExamsModule: React.FC<ExamsModuleProps> = ({ students, exams, subjects, payments }) => {
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [registrationMsg, setRegistrationMsg] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const handleRegister = (exam: Exam) => {
    if (!selectedStudentId) {
      setRegistrationMsg({ type: 'error', text: 'Seleccione un alumno primero.' });
      return;
    }

    const validation = validateExamRegistration(selectedStudentId, exam, payments);

    if (validation.allowed) {
      setRegistrationMsg({ type: 'success', text: 'Inscripción confirmada correctamente.' });
    } else {
      setRegistrationMsg({ type: 'error', text: validation.reason || 'No se pudo realizar la inscripción.' });
    }

    setTimeout(() => setRegistrationMsg(null), 4000);
  };

  return (
    <div className="space-y-6">
      <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex gap-3 items-start">
        <Info className="text-amber-600 shrink-0" size={20} />
        <div>
          <h4 className="font-bold text-amber-900 text-sm">Reglas de Examen</h4>
          <p className="text-xs text-amber-700 mt-1 leading-relaxed">
            Para que un alumno pueda inscribirse a un examen final: 
            1) Debe estar al día con sus cuotas (vencimiento día 10). 
            2) Debe inscribirse con al menos 48 horas de antelación a la fecha de la mesa.
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="font-bold text-slate-800 mb-4">Selección de Alumno</h3>
            <div className="space-y-4">
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Alumno Solicitante</label>
              <select 
                className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                value={selectedStudentId}
                onChange={e => setSelectedStudentId(e.target.value)}
              >
                <option value="">Seleccione...</option>
                {students.map(s => (
                  <option key={s.id} value={s.id}>{s.lastName}, {s.firstName} ({s.dni})</option>
                ))}
              </select>

              {selectedStudentId && (
                <div className="p-3 bg-slate-50 rounded-lg border border-slate-100">
                  <p className="text-xs text-slate-500 mb-1">Estado de Cuenta</p>
                  <p className="text-sm font-bold text-slate-700">Validando solvencia administrativa...</p>
                </div>
              )}
            </div>
          </div>

          {registrationMsg && (
            <div className={`p-4 rounded-xl border flex gap-3 animate-in fade-in slide-in-from-top-4 duration-300 ${
              registrationMsg.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-rose-50 border-rose-200 text-rose-700'
            }`}>
              {registrationMsg.type === 'success' ? <Check size={20} /> : <X size={20} />}
              <p className="text-sm font-medium">{registrationMsg.text}</p>
            </div>
          )}
        </div>

        <div className="lg:col-span-2">
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-6 border-b border-slate-100">
              <h3 className="font-bold text-slate-800">Mesas de Examen Disponibles</h3>
            </div>
            <div className="divide-y divide-slate-100">
              {exams.map(exam => {
                const subject = subjects.find(s => s.id === exam.subjectId);
                return (
                  <div key={exam.id} className="p-6 flex flex-col md:flex-row justify-between items-center gap-4 hover:bg-slate-50/50 transition-colors">
                    <div className="flex gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-lg flex flex-col items-center justify-center border border-slate-200">
                        <Calendar size={18} className="text-slate-500" />
