                      </div>
                      <div>
                        <p className="font-bold text-slate-800 text-lg">{subject?.name}</p>
                        <p className="text-sm text-slate-500 flex items-center gap-1">
                          <span className="font-semibold text-blue-600">{new Date(exam.date).toLocaleDateString('es-AR', { dateStyle: 'long' })}</span>
                          <span>•</span>
                          <span>Lugar: {exam.location}</span>
                        </p>
                      </div>
                    </div>
                    <button 
                      onClick={() => handleRegister(exam)}
                      className="px-6 py-2 bg-slate-900 text-white rounded-lg font-bold text-sm hover:bg-slate-800 transition-shadow hover:shadow-lg disabled:opacity-50"
                      disabled={!selectedStudentId}
                    >
                      Inscribirse a Mesa
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
