import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import StudentsModule from './components/StudentsModule';
import AcademicModule from './components/AcademicModule';
import BillingModule from './components/BillingModule';
import ExamsModule from './components/ExamsModule';
import { Student, Subject, Career, Payment, Exam, AcademicLevel } from './types';
import { INITIAL_STUDENTS, INITIAL_SUBJECTS, INITIAL_CAREERS } from './constants';
import { calculateMonthlyFee } from './utils';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('students');
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);

  // App State
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [subjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [careers] = useState<Career[]>(INITIAL_CAREERS);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [exams] = useState<Exam[]>([
    { id: 'e1', subjectId: 's2', date: '2023-12-15T09:00:00Z', location: 'Aula Magna' },
    { id: 'e2', subjectId: 's4', date: '2023-12-20T14:00:00Z', location: 'Lab de Computación' },
    { id: 'e3', subjectId: 's3', date: '2023-01-05T10:00:00Z', location: 'Aula 402' },
  ]);

  useEffect(() => {
    const today = new Date();
    const currentMonth = today.getMonth() + 1;
    const currentYear = today.getFullYear();

    const mockPayments: Payment[] = students.flatMap((s) => {
      const fee = calculateMonthlyFee(s);
      return [
        {
          id: `p-${s.id}-last`,
          studentId: s.id,
          amount: fee,
          month: currentMonth - 1,
          year: currentYear,
          dueDate: `${currentYear}-${(currentMonth - 1).toString().padStart(2, '0')}-10`,
          isPaid: true,
          paymentDate: `${currentYear}-${(currentMonth - 1).toString().padStart(2, '0')}-05`
        },
        {
          id: `p-${s.id}-curr`,
          studentId: s.id,
          amount: fee,
          month: currentMonth,
          year: currentYear,
          dueDate: `${currentYear}-${currentMonth.toString().padStart(2, '0')}-10`,
          isPaid: s.id === 'st1',
        }
      ];
    });
    setPayments(mockPayments);
  }, []);

  const handleAddStudent = (newStudentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...newStudentData,
      id: `st-${Date.now()}`,
    };
    setStudents([...students, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(students.filter(s => s.id !== id));
    setPayments(payments.filter(p => p.studentId !== id));
  };

  const handleTogglePayment = (paymentId: string) => {
    setPayments(payments.map(p => 
      p.id === paymentId ? { ...p, isPaid: !p.isPaid, paymentDate: !p.isPaid ? new Date().toISOString().split('T')[0] : undefined } : p
    ));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard students={students} payments={payments} />;
      case 'students':
        return (
          <StudentsModule 
            students={students} 
            careers={careers} 
            onAddStudent={handleAddStudent} 
            onDeleteStudent={handleDeleteStudent}
            isModalOpen={isStudentModalOpen}
            setIsModalOpen={setIsStudentModalOpen}
          />
        );
      case 'academic':
        return <AcademicModule subjects={subjects} careers={careers} />;
      case 'billing':
        return (
          <BillingModule 
            students={students} 
            payments={payments} 
            onTogglePayment={handleTogglePayment} 
          />
        );
      case 'exams':
        return (
          <ExamsModule 
            students={students} 
            exams={exams} 
            subjects={subjects} 
            payments={payments} 
          />
        );
      default:
        return <Dashboard students={students} payments={payments} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      onNewStudentClick={() => setIsStudentModalOpen(true)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

