                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all appearance-none"
                    value={formData.level}
                    onChange={e => setFormData({ ...formData, level: e.target.value as AcademicLevel, careerIds: [], grade: '' })}
                  >
                    {Object.values(AcademicLevel).map(l => (
                      <option key={l} value={l}>{l}</option>
                    ))}
                  </select>
                </div>
                {formData.level !== AcademicLevel.TERTIARY ? (
                  <div className="space-y-1.5">
                    <label className="text-sm font-bold text-slate-700">Grado / Año</label>
                    <input 
                      required
                      type="text" 
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                      placeholder="Ej: 1° Año B"
                      value={formData.grade}
                      onChange={e => setFormData({ ...formData, grade: e.target.value })}
                    />
                  </div>
                ) : (
                   <div className="space-y-1.5 col-span-1 md:col-span-2">
                    <label className="text-sm font-bold text-slate-700 mb-2 block">Selección de Carreras</label>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-200">
                      {careers.map(career => (
                        <label key={career.id} className="flex items-center gap-3 cursor-pointer p-2 hover:bg-white rounded-xl transition-all border border-transparent hover:border-slate-100">
                          <input 
                            type="checkbox" 
                            checked={formData.careerIds.includes(career.id)}
                            onChange={() => toggleCareer(career.id)}
                            className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500"
                          />
                          <span className="text-sm font-medium text-slate-700">{career.name}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="pt-6 flex gap-3">
                <button 
                  type="button" 
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-6 py-3 border border-slate-200 rounded-2xl text-slate-600 font-bold hover:bg-slate-50 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
                >
                  Registrar Alumno
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

