import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import StudentsModule from './components/StudentsModule';
import AcademicModule from './components/AcademicModule';
import BillingModule from './components/BillingModule';
import ExamsModule from './components/ExamsModule';
import { Student, Subject, Career, Payment, Exam, AcademicLevel } from './types';
import { INITIAL_STUDENTS, INITIAL_SUBJECTS, INITIAL_CAREERS } from './constants';
import { calculateMonthlyFee } from './utils';
import { LogIn, UserCircle, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<'admin' | 'student' | null>(null);
  const [currentStudentId, setCurrentStudentId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);

  // App State
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [subjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [careers] = useState<Career[]>(INITIAL_CAREERS);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [exams] = useState<Exam[]>([
    { id: 'e1', subjectId: 's2', date: '2023-12-15T09:00:00Z', location: 'Aula Magna' },
    { id: 'e2', subjectId: 's4', date: '2023-12-20T14:00:00Z', location: 'Lab de Computación' },
    { id: 'e3', subjectId: 's3', date: '2023-01-05T10:00:00Z', location: 'Aula 402' },
  ]);

  useEffect(() => {
    const today = new Date();
    const currentMonth = today.getMonth() + 1;
    const currentYear = today.getFullYear();

    const mockPayments: Payment[] = students.flatMap((s) => {
      const fee = calculateMonthlyFee(s);
      return [
        {
          id: `p-${s.id}-last`,
          studentId: s.id,
          amount: fee,
          month: currentMonth - 1,
          year: currentYear,
          dueDate: `${currentYear}-${(currentMonth - 1).toString().padStart(2, '0')}-10`,
          isPaid: true,
          paymentDate: `${currentYear}-${(currentMonth - 1).toString().padStart(2, '0')}-05`
        },
        {
          id: `p-${s.id}-curr`,
          studentId: s.id,
          amount: fee,
          month: currentMonth,
          year: currentYear,
          dueDate: `${currentYear}-${currentMonth.toString().padStart(2, '0')}-10`,
          isPaid: s.id === 'st1',
        }
      ];
    });
    setPayments(mockPayments);
  }, [students]);

  const handleLogin = (role: 'admin' | 'student', studentId?: string) => {
    setUserRole(role);
    if (role === 'student') {
      setCurrentStudentId(studentId || 'st4'); // Santiago López por defecto para demo
      setActiveTab('academic');
    } else {
      setActiveTab('dashboard');
    }
  };

  const handleLogout = () => {
    setUserRole(null);
    setCurrentStudentId(null);
  };

  const handleAddStudent = (newStudentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...newStudentData,
      id: `st-${Date.now()}`,
    };
    setStudents([...students, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(students.filter(s => s.id !== id));
    setPayments(payments.filter(p => p.studentId !== id));
  };

  const handleTogglePayment = (paymentId: string) => {
    setPayments(payments.map(p => 
      p.id === paymentId ? { ...p, isPaid: !p.isPaid, paymentDate: !p.isPaid ? new Date().toISOString().split('T')[0] : undefined } : p
    ));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100">
          <div className="bg-indigo-600 p-10 text-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 backdrop-blur-md">
              <LogIn size={32} />
            </div>
            <h1 className="text-2xl font-bold text-white">EduManager Pro</h1>
            <p className="text-indigo-100 text-sm mt-2">Bienvenido al sistema de gestión escolar</p>
          </div>
          <div className="p-8 space-y-4">
            <p className="text-center text-slate-500 text-sm mb-6">Seleccione su perfil de ingreso</p>
            <button 
              onClick={() => handleLogin('admin')}
              className="w-full flex items-center justify-between p-4 rounded-2xl border border-slate-200 hover:border-indigo-600 hover:bg-indigo-50 transition-all group"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-100 rounded-xl flex items-center justify-center text-indigo-600 group-hover:bg-indigo-600 group-hover:text-white transition-all">
                  <ShieldCheck size={24} />
                </div>
                <div className="text-left">
                  <p className="font-bold text-slate-800">Super Administrador</p>
                  <p className="text-xs text-slate-400">Acceso total a la institución</p>
                </div>
              </div>
            </button>
            <button 
              onClick={() => handleLogin('student')}
              className="w-full flex items-center justify-between p-4 rounded-2xl border border-slate-200 hover:border-emerald-600 hover:bg-emerald-50 transition-all group"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-emerald-100 rounded-xl flex items-center justify-center text-emerald-600 group-hover:bg-emerald-600 group-hover:text-white transition-all">
                  <UserCircle size={24} />
                </div>
                <div className="text-left">
                  <p className="font-bold text-slate-800">Acceso Alumno</p>
                  <p className="text-xs text-slate-400">Consulta académica y pagos</p>
                </div>
              </div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return userRole === 'admin' ? <Dashboard students={students} payments={payments} /> : null;
      case 'students':
        return userRole === 'admin' ? (
          <StudentsModule 
            students={students} 
            careers={careers} 
            onAddStudent={handleAddStudent} 
            onDeleteStudent={handleDeleteStudent}
            isModalOpen={isStudentModalOpen}
            setIsModalOpen={setIsStudentModalOpen}
          />
        ) : null;
      case 'academic':
        // Si es alumno, filtramos por sus carreras
        const filteredSubjects = userRole === 'student' && currentStudentId
          ? subjects.filter(sub => {
              const student = students.find(s => s.id === currentStudentId);
              return student?.careerIds.includes(sub.careerId || '') || sub.level === student?.level;
            })
          : subjects;
        return <AcademicModule subjects={filteredSubjects} careers={careers} isStudentView={userRole === 'student'} />;
      case 'billing':
        const filteredPayments = userRole === 'student' 
          ? payments.filter(p => p.studentId === currentStudentId)
          : payments;
        return (
          <BillingModule 
            students={students} 
            payments={filteredPayments} 
            onTogglePayment={handleTogglePayment}
            isAdmin={userRole === 'admin'}
          />
        );
      case 'exams':
        return (
          <ExamsModule 
            students={userRole === 'student' ? students.filter(s => s.id === currentStudentId) : students} 
            exams={exams} 
            subjects={subjects} 
            payments={payments}
            preselectedStudentId={currentStudentId || undefined}
          />
        );
      default:
        return userRole === 'admin' ? <Dashboard students={students} payments={payments} /> : null;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      onNewStudentClick={userRole === 'admin' ? () => setIsStudentModalOpen(true) : undefined}
      userRole={userRole}
      onLogout={handleLogout}
      userName={userRole === 'admin' ? 'Super Admin' : students.find(s => s.id === currentStudentId)?.firstName + ' ' + students.find(s => s.id === currentStudentId)?.lastName}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

