import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import { Profile } from './types';

interface AuthContextType {
  user: any | null;
  profile: Profile | null;
  loading: boolean;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      if (session?.user) fetchProfile(session.user.id);
      else setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) fetchProfile(session.user.id);
      else {
        setProfile(null);
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', userId)
      .single();

    if (!error) setProfile(data);
    setLoading(false);
  };

  const signOut = async () => {
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, loading, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

import { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

interface PaginatedResult<T> {
  data: T[];
  count: number;
  loading: boolean;
  error: any;
  page: number;
  setPage: (page: number) => void;
}

export function usePaginatedQuery<T>(
  table: string,
  schoolId: string | undefined,
  pageSize: number = 25,
  filters: Record<string, any> = {}
): PaginatedResult<T> {
  const [data, setData] = useState<T[]>([]);
  const [count, setCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(0);

  useEffect(() => {
    if (!schoolId) return;

    async function fetchData() {
      setLoading(true);
      const from = page * pageSize;
      const to = from + pageSize - 1;

      let query = supabase
        .from(table)
        .select('*', { count: 'exact' })
        .eq('school_id', schoolId)
        .range(from, to)
        .order('created_at', { ascending: false });

      // Apply extra filters
      Object.entries(filters).forEach(([key, value]) => {
        if (value) query = query.eq(key, value);
      });

      const { data: fetchedData, count: totalCount, error: fetchError } = await query;

      if (fetchError) setError(fetchError as any);
      else {
        setData(fetchedData as T[]);
        setCount(totalCount || 0);
      }
      setLoading(false);
    }

    fetchData();
  }, [table, schoolId, page, pageSize, JSON.stringify(filters)]);

  return { data, count, loading, error, page, setPage };
}

