import React, { Suspense, useState } from 'react';
import { AuthProvider, useAuth } from './authContext';
import Layout from './components/Layout';
import Dashboard from './Dashboard';
import StudentsModule from './components/StudentsModule';
import { supabase } from './supabaseClient';
import { LogIn, ShieldAlert, Loader2, Mail, CheckCircle2, AlertCircle } from 'lucide-react';

const LoginForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleMagicLinkLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    try {
      const { error } = await supabase.auth.signInWithOtp({
        email,
        options: {
          emailRedirectTo: window.location.origin,
        },
      });

      if (error) throw error;

      setMessage({
        type: 'success',
        text: '¡Enlace enviado! Revisa tu bandeja de entrada para iniciar sesión.'
      });
    } catch (error: any) {
      setMessage({
        type: 'error',
        text: error.message || 'Ocurrió un error al intentar enviar el enlace.'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100 transition-all">
        <div className="bg-indigo-600 p-10 text-center relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-2xl"></div>
          <h1 className="text-2xl font-bold text-white relative z-10">EduManager Pro</h1>
          <p className="text-indigo-100 text-sm mt-2 relative z-10">Acceso al Ecosistema Escolar</p>
        </div>

        <div className="p-8 space-y-6">
          <form onSubmit={handleMagicLinkLogin} className="space-y-4">
            <div className="space-y-2">
              <label htmlFor="email" className="text-sm font-bold text-slate-700 ml-1">
                Correo Electrónico
              </label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  id="email"
                  type="email"
                  placeholder="nombre@escuela.com"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-sm"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-700 disabled:bg-indigo-400 disabled:cursor-not-allowed transition-all shadow-lg shadow-indigo-100"
            >
              {loading ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  Enviando enlace...
                </>
              ) : (
                <>
                  <LogIn size={20} />
                  Enviar Magic Link
                </>
              )}
            </button>
          </form>

          {message && (
            <div className={`p-4 rounded-2xl flex items-start gap-3 animate-in fade-in slide-in-from-top-2 duration-300 ${
              message.type === 'success' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'
            }`}>
              {message.type === 'success' ? (
                <CheckCircle2 className="shrink-0 mt-0.5" size={18} />
              ) : (
                <AlertCircle className="shrink-0 mt-0.5" size={18} />
              )}
              <p className="text-xs font-medium leading-relaxed">{message.text}</p>
            </div>
          )}

          <div className="pt-4 border-t border-slate-100 text-center">
            <p className="text-xs text-slate-400 font-medium italic">
              Recibirás un correo con un botón para entrar sin contraseña.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

const AppContent: React.FC = () => {
  const { user, profile, loading, signOut } = useAuth();
  const [activeTab, setActiveTab] = React.useState('dashboard');

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50">
      <div className="text-center">
        <Loader2 className="animate-spin text-indigo-600 mx-auto mb-4" size={48} />
        <p className="text-slate-500 font-medium">Cargando ecosistema escolar...</p>
      </div>
    </div>
  );

  if (!user) {
    return <LoginForm />;
  }

  if (!profile) return (
    <div className="min-h-screen flex items-center justify-center p-6 text-center">
      <div className="max-w-md">
        <ShieldAlert size={64} className="text-rose-500 mx-auto mb-4" />
        <h2 className="text-2xl font-bold text-slate-800">Perfil no encontrado</h2>
        <p className="text-slate-500 mt-2">
          Has iniciado sesión correctamente, pero no pareces tener un perfil de usuario configurado en nuestra base de datos.
        </p>
        <div className="mt-8 p-4 bg-amber-50 rounded-2xl border border-amber-100 text-left">
          <p className="text-xs text-amber-800 font-medium">
            <strong>Nota para administradores:</strong> Asegúrate de que exista una entrada en la tabla <code className="bg-amber-100 px-1 rounded">profiles</code> vinculando el UUID <code>{user.id}</code> con un <code>school_id</code> válido.
          </p>
        </div>
        <button 
          onClick={signOut} 
          className="mt-6 text-indigo-600 font-bold hover:underline flex items-center justify-center gap-2 mx-auto"
        >
          Cerrar Sesión e intentar con otra cuenta
        </button>
      </div>
    </div>
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard schoolId={profile.school_id} />;
      case 'students': return <StudentsModule schoolId={profile.school_id} />;
      default: return <Dashboard schoolId={profile.school_id} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={profile.role} 
      userName={profile.full_name}
      onLogout={signOut}
    >
      <Suspense fallback={
        <div className="flex items-center justify-center h-64">
          <Loader2 className="animate-spin text-indigo-600" size={32} />
        </div>
      }>
        {renderContent()}
      </Suspense>
    </Layout>
  );
};

const App: React.FC = () => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

export default App;

import { createClient } from '@supabase/supabase-js';
import { INITIAL_STUDENTS, INITIAL_CAREERS } from './constants';

const supabaseUrl = (window as any)._env_?.SUPABASE_URL || 'https://your-project.supabase.co';
const supabaseAnonKey = (window as any)._env_?.SUPABASE_ANON_KEY || 'your-anon-key';

// Si las credenciales son las por defecto, usamos un Mock para evitar "Failed to fetch"
const isMockMode = supabaseUrl.includes('your-project') || supabaseAnonKey === 'your-anon-key';

const createMockSupabase = () => {
  return {
    auth: {
      getSession: async () => ({ data: { session: null }, error: null }),
      onAuthStateChange: (cb: any) => ({ data: { subscription: { unsubscribe: () => {} } } }),
      signInWithOtp: async () => ({ data: {}, error: null }),
      signOut: async () => ({ error: null }),
    },
    from: (table: string) => ({
      select: (query: string, options: any) => ({
        eq: (col: string, val: any) => ({
          single: async () => {
            if (table === 'profiles') return { data: { id: val, school_id: 'school-1', role: 'school_admin', full_name: 'Admin Demostración' }, error: null };
            if (table === 'school_stats') return { data: { total_students: 245, active_students: 230, total_revenue_month: 450000, pending_payments_count: 12 }, error: null };
            return { data: null, error: null };
          },
          range: (from: number, to: number) => ({
            order: (col: string, opt: any) => ({
              then: (cb: any) => {
                let data: any[] = [];
                if (table === 'students') data = INITIAL_STUDENTS;
                if (table === 'careers') data = INITIAL_CAREERS;
                return Promise.resolve({ data: data.slice(from, to + 1), count: data.length, error: null });
              }
            })
          })
        })
      })
    })
  } as any;
};

export const supabase = isMockMode ? createMockSupabase() : createClient(supabaseUrl, supabaseAnonKey);

import React, { useState } from 'react';
import { Plus, Search, Filter, MoreHorizontal, Users, X, Loader2 } from 'lucide-react';
import { Student, AcademicLevel, Career } from '../types';
import { usePaginatedQuery } from '../usePaginatedQuery';
