  const getAvatarColor = (index: number) => {
    const colors = ['bg-indigo-500', 'bg-purple-500', 'bg-blue-500', 'bg-violet-500', 'bg-indigo-400'];
    return colors[index % colors.length];
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log('Guardando alumno...', formData);
    setIsModalOpen(false);
  };

  const toggleCareer = (careerId: string) => {
    const current = formData.careerIds;
    if (current.includes(careerId)) {
      setFormData({ ...formData, careerIds: current.filter(id => id !== careerId) });
    } else {
      setFormData({ ...formData, careerIds: [...current, careerId] });
    }
