              className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium disabled:opacity-50"
            >
              Anterior
            </button>
            <button 
              disabled={(page + 1) * 25 >= count}
              onClick={() => setPage(page + 1)}
              className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium disabled:opacity-50"
            >
              Siguiente
            </button>
          </div>
        </div>
