                </select>
                {formData.level === AcademicLevel.TERTIARY && (
                  <div className="col-span-2 space-y-2">
                    <p className="text-xs font-bold text-slate-500 uppercase">Carreras Disponibles</p>
                    <div className="grid grid-cols-2 gap-2">
                      {INITIAL_CAREERS.map(c => (
                        <label key={c.id} className="flex items-center gap-2 p-2 bg-slate-50 rounded-lg cursor-pointer">
                          <input type="checkbox" checked={formData.careerIds.includes(c.id)} onChange={() => toggleCareer(c.id)} />
