// Estado global para el mock (solo en memoria)
let mockUser: any = null;
let authChangeListeners: Array<(event: string, session: any) => void> = [];

const createMockSupabase = () => {
  return {
    auth: {
      getSession: async () => ({ 
        data: { session: mockUser ? { user: mockUser } : null }, 
        error: null 
      }),
      onAuthStateChange: (cb: any) => {
        authChangeListeners.push(cb);
        // Llamada inicial
        cb('INITIAL_SESSION', mockUser ? { user: mockUser } : null);
        return { data: { subscription: { unsubscribe: () => {
          authChangeListeners = authChangeListeners.filter(l => l !== cb);
        } } } };
      },
      signInWithOtp: async ({ email }: { email: string }) => {
        // Simulamos que el login es exitoso
        mockUser = { id: 'mock-user-id', email: email };
        authChangeListeners.forEach(l => l('SIGNED_IN', { user: mockUser }));
        return { data: {}, error: null };
      },
      signOut: async () => {
        mockUser = null;
        authChangeListeners.forEach(l => l('SIGNED_OUT', null));
        return { error: null };
      },
    },
    from: (table: string) => ({
      select: (query: string, options: any) => ({
        eq: (col: string, val: any) => ({
          single: async () => {
            if (table === 'profiles') {
              // Si el email contiene superadmin, damos ese rol
              const isSuper = mockUser?.email?.includes('superadmin');
              return { 
                data: { 
                  id: val, 
                  school_id: 'school-1', 
                  role: isSuper ? 'superadmin' : 'school_admin', 
                  full_name: isSuper ? 'Superadministrador Global' : 'Admin Demostración' 
                }, 
                error: null 
              };
            }
            if (table === 'school_stats') return { data: { total_students: 245, active_students: 230, total_revenue_month: 450000, pending_payments_count: 12 }, error: null };
            return { data: null, error: null };
          },
          range: (from: number, to: number) => ({
            order: (col: string, opt: any) => ({
              then: (cb: any) => {
                let data: any[] = [];
                if (table === 'students') data = INITIAL_STUDENTS;
                if (table === 'careers') data = INITIAL_CAREERS;
                return Promise.resolve({ data: data.slice(from, to + 1), count: data.length, error: null });
              }
            })
          })
        })
      })
    })
  } as any;
};

export const supabase = isMockMode ? createMockSupabase() : createClient(supabaseUrl, supabaseAnonKey);

