import { createClient } from '@supabase/supabase-js';
import { INITIAL_STUDENTS, INITIAL_CAREERS, INITIAL_SUBJECTS } from './constants';

const supabaseUrl = (window as any)._env_?.SUPABASE_URL || 'https://your-project.supabase.co';
const supabaseAnonKey = (window as any)._env_?.SUPABASE_ANON_KEY || 'your-anon-key';

const isMockMode = supabaseUrl.includes('your-project') || supabaseAnonKey === 'your-anon-key';

// Almacenamiento volátil para la demo
let studentsDB = [...INITIAL_STUDENTS];
let mockUser: any = null;
let authChangeListeners: Array<(event: string, session: any) => void> = [];

const createMockSupabase = () => {
  const chainable = (table: string, filters: any = {}) => {
    const obj = {
      select: () => obj,
      eq: (col: string, val: any) => {
        filters[col] = val;
        return obj;
      },
      range: (from: number, to: number) => {
        obj._range = [from, to];
        return obj;
      },
      order: () => obj,
      single: async () => {
        if (table === 'profiles') {
          const isSuper = mockUser?.email?.includes('superadmin');
          return { 
            data: { 
              id: filters.id || 'mock-id', 
              school_id: 'school-1', 
              role: isSuper ? 'superadmin' : 'school_admin', 
              full_name: isSuper ? 'Superadmin Demo' : 'Admin Demo' 
            }, 
            error: null 
          };
        }
        if (table === 'school_stats') return { data: { total_students: studentsDB.length, active_students: studentsDB.filter(s => s.status === 'ACTIVE').length, total_revenue_month: 450000, pending_payments_count: 12 }, error: null };
        return { data: null, error: null };
      },
      // Soporte para await directo sobre el objeto encadenado
      then: (onfulfilled: any) => {
        let data: any[] = [];
        if (table === 'students') data = [...studentsDB];
        if (table === 'careers') data = [...INITIAL_CAREERS];
        if (table === 'subjects') data = [...INITIAL_SUBJECTS];

        // Aplicar filtros básicos si existen
        const filteredData = data.filter(item => {
          return Object.entries(filters).every(([k, v]) => !v || item[k] === v);
        });

        const result = {
          data: obj._range ? filteredData.slice(obj._range[0], obj._range[1] + 1) : filteredData,
          count: filteredData.length,
          error: null
        };
        return Promise.resolve(onfulfilled(result));
      },
      _range: null as number[] | null
    };
    return obj;
  };

  return {
    auth: {
      getSession: async () => ({ data: { session: mockUser ? { user: mockUser } : null }, error: null }),
      onAuthStateChange: (cb: any) => {
        authChangeListeners.push(cb);
        cb('INITIAL_SESSION', mockUser ? { user: mockUser } : null);
        return { data: { subscription: { unsubscribe: () => { authChangeListeners = authChangeListeners.filter(l => l !== cb); } } } };
      },
      signInWithOtp: async ({ email }: { email: string }) => {
        mockUser = { id: 'mock-user-id', email };
        authChangeListeners.forEach(l => l('SIGNED_IN', { user: mockUser }));
        return { data: {}, error: null };
      },
      signOut: async () => {
        mockUser = null;
        authChangeListeners.forEach(l => l('SIGNED_OUT', null));
        return { error: null };
      },
    },
    from: (table: string) => ({
      ...chainable(table),
      insert: async (data: any) => {
        if (table === 'students') {
          const newStudent = { ...data, id: `st-${Math.random()}`, school_id: 'school-1', created_at: new Date().toISOString() };
          studentsDB.unshift(newStudent);
          return { data: [newStudent], error: null };
        }
        return { data: [], error: null };
      }
    })
  } as any;
};

export const supabase = isMockMode ? createMockSupabase() : createClient(supabaseUrl, supabaseAnonKey);

import React, { useState } from 'react';
import { Plus, Search, Filter, MoreHorizontal, Users, X, Loader2, AlertCircle } from 'lucide-react';
import { Student, AcademicLevel, Career } from '../types';
import { usePaginatedQuery } from '../usePaginatedQuery';
import { INITIAL_CAREERS } from '../constants';
import { supabase } from '../supabaseClient';

interface StudentsModuleProps {
  schoolId: string;
}

const StudentsModule: React.FC<StudentsModuleProps> = ({ schoolId }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [levelFilter, setLevelFilter] = useState<AcademicLevel | 'ALL'>('ALL');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);

  const { data: students, loading, count, page, setPage } = usePaginatedQuery<Student>(
    'students',
    schoolId,
    25,
    levelFilter !== 'ALL' ? { level: levelFilter } : {}
  );

  const [formData, setFormData] = useState<Omit<Student, 'id' | 'school_id'>>({
    dni: '',
    firstName: '',
    lastName: '',
    email: '',
    level: AcademicLevel.INITIAL,
    careerIds: [],
    grade: '',
    enrollmentDate: new Date().toISOString().split('T')[0],
    status: 'ACTIVE'
  });

  const validate = () => {
    if (formData.dni.length < 7 || formData.dni.length > 8 || !/^\d+$/.test(formData.dni)) {
      return "El DNI debe tener entre 7 y 8 números.";
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      return "Ingrese un correo electrónico válido.";
    }
    if (!formData.firstName || !formData.lastName) {
      return "Nombre y Apellido son obligatorios.";
    }
    return null;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const error = validate();
    if (error) {
      setValidationError(error);
      return;
    }

    setValidationError(null);
    setIsSaving(true);

    try {
      const { error: dbError } = await supabase.from('students').insert({
        ...formData,
        school_id: schoolId
      });

      if (dbError) throw dbError;

      setIsModalOpen(false);
      // Forzamos un pequeño delay para la sensación de guardado
      setTimeout(() => {
        window.location.reload(); // Recarga simple para reflejar cambios en la demo
      }, 500);
    } catch (err) {
      setValidationError("Error al guardar el alumno.");
    } finally {
      setIsSaving(false);
    }
  };

  const toggleCareer = (careerId: string) => {
    const current = formData.careerIds;
    if (current.includes(careerId)) {
      setFormData({ ...formData, careerIds: current.filter(id => id !== careerId) });
    } else {
      setFormData({ ...formData, careerIds: [...current, careerId] });
    }
  };

  const getLevelBadgeStyles = (level: AcademicLevel) => {
    switch (level) {
      case AcademicLevel.INITIAL: return 'bg-pink-100 text-pink-600';
      case AcademicLevel.PRIMARY: return 'bg-blue-100 text-blue-600';
      case AcademicLevel.SECONDARY: return 'bg-orange-100 text-orange-600';
      case AcademicLevel.TERTIARY: return 'bg-emerald-100 text-emerald-600';
      default: return 'bg-slate-100 text-slate-600';
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-start">
        <div className="flex items-center gap-4">
          <div className="text-indigo-600 bg-indigo-50 p-3 rounded-2xl">
            <Users size={32} strokeWidth={1.5} />
          </div>
          <div>
            <h2 className="text-3xl font-bold text-slate-800 tracking-tight">Alumnos</h2>
            <p className="text-slate-500 mt-1">Gestión del alumnado de la institución</p>
          </div>
        </div>
        <button 
          onClick={() => {
            setValidationError(null);
            setIsModalOpen(true);
          }}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={20} />
          Nuevo Alumno
        </button>
      </div>

      <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row gap-4 items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por nombre, DNI o email..." 
            className="pl-12 pr-4 py-2.5 w-full bg-slate-50/50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <div className="relative">
            <select 
              className="appearance-none bg-slate-50/50 border border-slate-200 rounded-xl pl-10 pr-10 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 min-w-[180px]"
              value={levelFilter}
              onChange={(e) => setLevelFilter(e.target.value as AcademicLevel | 'ALL')}
            >
              <option value="ALL">Todos los niveles</option>
              {Object.values(AcademicLevel).map(l => (
                <option key={l} value={l}>{l}</option>
              ))}
            </select>
            <Filter className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden relative min-h-[400px]">
        {loading && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] z-10 flex items-center justify-center">
            <Loader2 className="animate-spin text-indigo-600" size={40} />
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/80 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-[13px] font-bold text-slate-400 uppercase tracking-wide">Alumno</th>
                <th className="px-6 py-4 text-[13px] font-bold text-slate-400 uppercase tracking-wide">DNI</th>
                <th className="px-6 py-4 text-[13px] font-bold text-slate-400 uppercase tracking-wide">Nivel</th>
                <th className="px-6 py-4 text-[13px] font-bold text-slate-400 uppercase tracking-wide">Estado</th>
                <th className="px-6 py-4 text-[13px] font-bold text-slate-400 uppercase tracking-wide text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {students.length > 0 ? students.map((student, idx) => (
                <tr key={student.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-5">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white text-xs font-bold shadow-sm`}>
                        {student.firstName[0]}{student.lastName[0]}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-[15px]">{student.firstName} {student.lastName}</span>
                        <span className="text-[13px] text-slate-400">{student.email}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    <span className="text-slate-500 font-medium text-[14px] tracking-tight">{student.dni}</span>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`text-[12px] px-3 py-1 rounded-lg font-bold ${getLevelBadgeStyles(student.level)}`}>
                      {student.level}
                    </span>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`inline-flex items-center px-3 py-1 rounded-lg text-[12px] font-bold border ${student.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600 border-emerald-100/50' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                      {student.status === 'ACTIVE' ? 'Activo' : 'Inactivo'}
                    </span>
                  </td>
                  <td className="px-6 py-5 text-right">
                    <button className="p-2 text-slate-300 hover:text-slate-600 transition-colors rounded-lg hover:bg-slate-100">
                      <MoreHorizontal size={20} />
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-slate-400">
                    No se encontraron alumnos registrados.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
          <p className="text-sm text-slate-500">Mostrando {students.length} de {count} alumnos</p>
          <div className="flex gap-2">
            <button 
              disabled={page === 0}
              onClick={() => setPage(page - 1)}
              className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium disabled:opacity-50"
            >
              Anterior
            </button>
            <button 
              disabled={(page + 1) * 25 >= count}
              onClick={() => setPage(page + 1)}
              className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium disabled:opacity-50"
            >
              Siguiente
            </button>
          </div>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => !isSaving && setIsModalOpen(false)}></div>
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden relative z-10 flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
              <h3 className="text-xl font-bold">Inscribir Nuevo Alumno</h3>
              <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-indigo-500 rounded-xl transition-colors">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 overflow-y-auto space-y-5">
              {validationError && (
                <div className="p-3 bg-rose-50 text-rose-600 rounded-xl border border-rose-100 flex items-center gap-2 text-sm font-medium">
                  <AlertCircle size={18} />
                  {validationError}
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">Nombre</label>
                  <input required placeholder="Ej: Juan" className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.firstName} onChange={e => setFormData({ ...formData, firstName: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">Apellido</label>
                  <input required placeholder="Ej: Pérez" className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.lastName} onChange={e => setFormData({ ...formData, lastName: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">DNI (7 u 8 dígitos)</label>
                  <input required placeholder="Sin puntos" className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.dni} onChange={e => setFormData({ ...formData, dni: e.target.value.replace(/\D/g, '').slice(0, 8) })} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">Email</label>
                  <input required placeholder="juan@ejemplo.com" type="email" className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">Nivel Académico</label>
                  <select className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.level} onChange={e => setFormData({ ...formData, level: e.target.value as AcademicLevel })}>
                     {Object.values(AcademicLevel).map(l => <option key={l} value={l}>{l}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 ml-1">Grado / Año</label>
                  <input placeholder="Ej: 1° A" className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500" value={formData.grade} onChange={e => setFormData({ ...formData, grade: e.target.value })} />
                </div>

                {formData.level === AcademicLevel.TERTIARY && (
                  <div className="col-span-2 space-y-2 pt-2 border-t border-slate-100">
                    <p className="text-xs font-bold text-slate-500 uppercase">Carreras Disponibles</p>
                    <div className="grid grid-cols-2 gap-2">
                      {INITIAL_CAREERS.map(c => (
                        <label key={c.id} className="flex items-center gap-2 p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition-colors">
                          <input type="checkbox" className="w-4 h-4 text-indigo-600 rounded" checked={formData.careerIds.includes(c.id)} onChange={() => toggleCareer(c.id)} />
                          <span className="text-xs font-medium text-slate-700">{c.name}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="pt-6 flex gap-3">
                <button type="button" disabled={isSaving} onClick={() => setIsModalOpen(false)} className="flex-1 px-6 py-4 border border-slate-200 rounded-2xl text-slate-600 font-bold hover:bg-slate-50 transition-all disabled:opacity-50">Cancelar</button>
                <button type="submit" disabled={isSaving} className="flex-1 px-6 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center justify-center gap-2">
                  {isSaving ? <Loader2 className="animate-spin" size={20} /> : 'Registrar Alumno'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

