import React, { Suspense, useState } from 'react';
import { AuthProvider, useAuth } from './authContext';
import Layout from './components/Layout';
import Dashboard from './Dashboard';
import StudentsModule from './components/StudentsModule';
import AcademicModule from './components/AcademicModule';
import ExamsModule from './components/ExamsModule';
import BillingModule from './components/BillingModule';
import { supabase } from './supabaseClient';
import { INITIAL_STUDENTS, INITIAL_SUBJECTS, INITIAL_CAREERS } from './constants';
import { LogIn, ShieldAlert, Loader2, Mail, CheckCircle2, AlertCircle, ShieldCheck } from 'lucide-react';

const LoginForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleMagicLinkLogin = async (e?: React.FormEvent, customEmail?: string) => {
    if (e) e.preventDefault();
    const targetEmail = customEmail || email;

    setLoading(true);
    setMessage(null);

    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: targetEmail,
        options: {
          emailRedirectTo: window.location.origin,
        },
      });

      if (error) throw error;

      setMessage({
        type: 'success',
        text: '¡Sesión iniciada! Redirigiendo...'
      });
    } catch (error: any) {
      setMessage({
        type: 'error',
        text: error.message || 'Ocurrió un error al intentar iniciar sesión.'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100 transition-all">
        <div className="bg-indigo-600 p-10 text-center relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-2xl"></div>
          <h1 className="text-2xl font-bold text-white relative z-10">EduManager Pro</h1>
          <p className="text-indigo-100 text-sm mt-2 relative z-10">Acceso al Ecosistema Escolar</p>
        </div>

        <div className="p-8 space-y-6">
          <form onSubmit={(e) => handleMagicLinkLogin(e)} className="space-y-4">
            <div className="space-y-2">
              <label htmlFor="email" className="text-sm font-bold text-slate-700 ml-1">
                Correo Electrónico
              </label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  id="email"
                  type="email"
                  placeholder="nombre@escuela.com"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-sm"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-700 disabled:bg-indigo-400 disabled:cursor-not-allowed transition-all shadow-lg shadow-indigo-100"
            >
              {loading ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  Procesando...
                </>
              ) : (
                <>
                  <LogIn size={20} />
                  Enviar Magic Link
                </>
              )}
            </button>
          </form>

          <div className="relative">
            <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-slate-100"></span></div>
            <div className="relative flex justify-center text-xs uppercase"><span className="bg-white px-2 text-slate-400 font-bold">Modo Demo</span></div>
          </div>

          <button
            onClick={() => handleMagicLinkLogin(undefined, 'superadmin@edumanager.pro')}
            className="w-full bg-slate-800 text-white p-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-slate-900 transition-all shadow-lg shadow-slate-200"
          >
            <ShieldCheck size={20} />
            Acceso Superadmin de Prueba
          </button>

          {message && (
            <div className={`p-4 rounded-2xl flex items-start gap-3 animate-in fade-in slide-in-from-top-2 duration-300 ${
              message.type === 'success' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-rose-50 text-rose-700 border border-rose-100'
            }`}>
              {message.type === 'success' ? (
                <CheckCircle2 className="shrink-0 mt-0.5" size={18} />
              ) : (
                <AlertCircle className="shrink-0 mt-0.5" size={18} />
              )}
              <p className="text-xs font-medium leading-relaxed">{message.text}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const AppContent: React.FC = () => {
  const { user, profile, loading, signOut } = useAuth();
  const [activeTab, setActiveTab] = React.useState('dashboard');

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50">
      <div className="text-center">
        <Loader2 className="animate-spin text-indigo-600 mx-auto mb-4" size={48} />
        <p className="text-slate-500 font-medium">Cargando ecosistema escolar...</p>
      </div>
    </div>
  );

  if (!user) {
    return <LoginForm />;
  }

  if (!profile) return (
    <div className="min-h-screen flex items-center justify-center p-6 text-center">
      <div className="max-w-md">
        <ShieldAlert size={64} className="text-rose-500 mx-auto mb-4" />
        <h2 className="text-2xl font-bold text-slate-800">Perfil no encontrado</h2>
        <p className="text-slate-500 mt-2">
          Has iniciado sesión correctamente, pero no pareces tener un perfil configurado en este momento.
        </p>
        <button 
          onClick={signOut} 
          className="mt-6 text-indigo-600 font-bold hover:underline flex items-center justify-center gap-2 mx-auto"
        >
          Cerrar Sesión e intentar con otra cuenta
        </button>
      </div>
    </div>
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': 
        return <Dashboard schoolId={profile.school_id} />;
      case 'students': 
        return <StudentsModule schoolId={profile.school_id} />;
      case 'academic': 
        return <AcademicModule subjects={INITIAL_SUBJECTS} careers={INITIAL_CAREERS} />;
      case 'exams': 
        return <ExamsModule students={INITIAL_STUDENTS} exams={[]} subjects={INITIAL_SUBJECTS} payments={[]} />;
      case 'billing': 
        return <BillingModule students={INITIAL_STUDENTS} payments={[]} onTogglePayment={() => {}} isAdmin={profile.role !== 'student'} />;
      default: 
        return <Dashboard schoolId={profile.school_id} />;
    }
  };

  const layoutRole: 'admin' | 'student' = profile.role === 'student' ? 'student' : 'admin';

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={layoutRole} 
      userName={profile.full_name}
      onLogout={signOut}
    >
      <Suspense fallback={
        <div className="flex items-center justify-center h-64">
          <Loader2 className="animate-spin text-indigo-600" size={32} />
        </div>
      }>
        <div className="animate-in fade-in duration-300">
          {renderContent()}
        </div>
      </Suspense>
    </Layout>
  );
};

const App: React.FC = () => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

export default App;

