           <h1 className="text-3xl font-black tracking-tighter">EduManager Pro</h1>
           <p className="text-indigo-100 font-bold text-sm mt-2 opacity-80 uppercase tracking-widest">Acceso Institucional</p>
        </div>
        <div className="p-10 space-y-6">
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="email" 
              placeholder="nombre@escuela.com" 
              value={email} 
              onChange={e => setEmail(e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center justify-center gap-2">
              {loading ? <Loader2 className="animate-spin" /> : 'Entrar con Magic Link'}
            </button>
          </form>
          <div className="relative flex items-center"><span className="flex-1 border-t border-slate-100"></span><span className="mx-4 text-xs font-bold text-slate-300 uppercase">Demo</span><span className="flex-1 border-t border-slate-100"></span></div>
          <button onClick={() => handleLogin(null, 'superadmin@edumanager.pro')} className="w-full bg-slate-800 text-white p-4 rounded-2xl font-black hover:bg-slate-900 transition-all shadow-lg flex items-center justify-center gap-2">
            <ShieldCheck size={20} /> Acceso Superadmin de Prueba
          </button>
        </div>
      </div>
    </div>
  );
};

const AppContent = () => {
  const { user, profile, loading, signOut } = useAuth();
  const [activeTab, setActiveTab] = useState('dashboard');

  if (loading) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;
  if (!user) return <LoginForm />;
  if (!profile) return <div className="p-20 text-center"><ShieldAlert className="mx-auto text-rose-500" size={64} /><h2 className="text-xl font-bold mt-4">Perfil no encontrado</h2><button onClick={signOut} className="text-indigo-600 font-bold mt-4 underline">Cerrar Sesión</button></div>;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard schoolId={profile.school_id} />;
      case 'students-list': return <StudentsModule schoolId={profile.school_id} />;
      case 'new-student': return <NewStudentForm onCancel={() => setActiveTab('students-list')} onSave={() => setActiveTab('students-list')} />;
      case 'subjects': return <AcademicModule view="subjects" subjects={INITIAL_SUBJECTS} careers={INITIAL_CAREERS} enrollments={[]} />;
      case 'careers': return <AcademicModule view="careers" subjects={INITIAL_SUBJECTS} careers={INITIAL_CAREERS} enrollments={[]} />;
      case 'enrollments': return <AcademicModule view="enrollments" subjects={INITIAL_SUBJECTS} careers={INITIAL_CAREERS} enrollments={[]} />;
      case 'exams-schedule': return <ExamsModule view="schedule" exams={[]} />;
      case 'exams-enroll': return <ExamsModule view="enrollment" exams={[]} />;
      case 'fees': return <BillingModule view="fees" payments={INITIAL_PAYMENTS} />;
      case 'billing-config': return <BillingModule view="config" payments={[]} />;
      default: return <Dashboard schoolId={profile.school_id} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={profile.role} 
      userName={profile.full_name} 
      onLogout={signOut}
    >
      <Suspense fallback={<Loader2 className="animate-spin mx-auto mt-20" />}>
        {renderContent()}
      </Suspense>
    </Layout>
  );
};

const App = () => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

