      single: async () => {
        if (table === 'profiles') return { data: { id: filters.id, school_id: 'school-1', role: mockUser?.email?.includes('superadmin') ? 'superadmin' : 'school_admin', full_name: 'Juan Biscaldi' }, error: null };
        if (table === 'school_stats') return { data: { total_students: studentsDB.length, active_students: studentsDB.length, total_revenue_month: 1240000, pending_payments_count: 8 }, error: null };
        return { data: null, error: null };
      },
      then: (onfulfilled: any) => {
        let data: any[] = [];
        if (table === 'students') data = [...studentsDB];
        if (table === 'careers') data = [...careersDB];
        if (table === 'subjects') data = [...subjectsDB];
        if (table === 'payments') data = [...paymentsDB];
        if (table === 'exams') data = [...examsDB];
        if (table === 'enrollments') data = [...enrollmentsDB];

        const filtered = data.filter(i => Object.entries(filters).every(([k, v]) => !v || i[k] === v));
        return Promise.resolve(onfulfilled({
          data: obj._range ? filtered.slice(obj._range[0], obj._range[1] + 1) : filtered,
          count: filtered.length,
          error: null
        }));
      },
      _range: null as any
    };
    return obj;
  };

  return {
    auth: {
      getSession: async () => ({ data: { session: mockUser ? { user: mockUser } : null }, error: null }),
      onAuthStateChange: (cb: any) => { listeners.push(cb); cb('INITIAL', mockUser ? { user: mockUser } : null); return { data: { subscription: { unsubscribe: () => {} } } }; },
      signInWithOtp: async ({ email }: any) => { mockUser = { id: 'u1', email }; listeners.forEach(l => l('SIGNED_IN', { user: mockUser })); return { error: null }; },
      signOut: async () => { mockUser = null; listeners.forEach(l => l('SIGNED_OUT', null)); return { error: null }; }
    },
    from: (table: string) => ({
      ...chain(table),
      insert: async (data: any) => {
        const payload = Array.isArray(data) ? data : [data];
        payload.forEach(item => {
          const newItem = { 
            ...item, 
            id: item.id || `mock-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            created_at: new Date().toISOString()
          };
          if (table === 'students') studentsDB.unshift(newItem);
          if (table === 'subjects') subjectsDB.unshift(newItem);
          if (table === 'careers') careersDB.unshift(newItem);
          if (table === 'exams') examsDB.unshift(newItem);
          if (table === 'enrollments') enrollmentsDB.unshift(newItem);
        });
        return { data: payload, error: null };
      },
      update: async (data: any) => {
        return { error: null };
      },
      delete: () => ({
        eq: async (c: string, v: any) => {
          if (table === 'subjects') subjectsDB = subjectsDB.filter(s => s[c as keyof typeof s] !== v);
          if (table === 'careers') careersDB = careersDB.filter(s => s[c as keyof typeof s] !== v);
          if (table === 'students') studentsDB = studentsDB.filter(s => s[c as keyof typeof s] !== v);
          if (table === 'exams') examsDB = examsDB.filter(e => e[c as keyof typeof e] !== v);
          if (table === 'enrollments') enrollmentsDB = enrollmentsDB.filter(e => e[c as keyof typeof e] !== v);
          return { error: null };
        }
      })
    })
  } as any;
};

export const supabase = isMockMode ? createMockSupabase() : createClient(supabaseUrl, supabaseAnonKey);

