import React, { useState } from 'react';
import { ClipboardList, Plus, AlertTriangle, Trash2, X, Loader2, Save, Edit3 } from 'lucide-react';
import { Exam, INITIAL_STUDENTS } from '../types';
import { supabase } from '../supabaseClient';

interface ExamsModuleProps {
  view: 'schedule' | 'enrollment';
  exams: Exam[];
}

const ExamsModule: React.FC<ExamsModuleProps> = ({ view, exams: initialExams }) => {
  const [exams, setExams] = useState<Exam[]>(initialExams);
  const [enrollments, setEnrollments] = useState<any[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);

  const [examData, setExamData] = useState<Partial<Exam>>({
    subjectId: '', type: 'Parcial', date: '', closingDate: '', location: '', status: 'Programado'
  });

  const [enrollmentData, setEnrollmentData] = useState({
    studentId: '', examId: '', status: 'Inscripto'
  });

  const handleAddExam = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...examData, id: `e-${Date.now()}` };
    await supabase.from('exams').insert(newItem);
    setExams([newItem as Exam, ...exams]);
    setLoading(false);
    setIsModalOpen(false);
    setExamData({ subjectId: '', type: 'Parcial', date: '', closingDate: '', location: '', status: 'Programado' });
  };

  const handleAddEnrollment = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...enrollmentData, id: `ere-${Date.now()}`, date: new Date().toISOString() };
    await supabase.from('enrollments').insert(newItem);
    setEnrollments([newItem, ...enrollments]);
    setLoading(false);
    setIsModalOpen(false);
    setEnrollmentData({ studentId: '', examId: '', status: 'Inscripto' });
  };

  const handleDelete = async (table: string, id: string) => {
    if (!confirm('¿Seguro que desea eliminar este registro?')) return;
    await supabase.from(table).delete().eq('id', id);
    if (table === 'exams') setExams(exams.filter(e => e.id !== id));
    if (table === 'enrollments') setEnrollments(enrollments.filter(e => e.id !== id));
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno';
  };

  const getExamSubject = (id: string) => {
    const ex = exams.find(e => e.id === id);
    return ex ? ex.subjectId : 'Examen';
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="text-indigo-600"><ClipboardList size={28} /></div>
          <div>
            <h2 className="text-2xl font-bold text-[#1E293B]">
              {view === 'schedule' ? 'Mesa de Exámenes' : 'Inscripciones a Exámenes'}
            </h2>
            <p className="text-xs text-slate-400 font-bold uppercase">
              {view === 'schedule' ? 'Programación de exámenes y mesas' : 'Gestión de inscripciones a mesas de examen'}
            </p>
          </div>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 font-bold shadow-lg shadow-indigo-100"
        >
          <Plus size={20} /> Nueva {view === 'schedule' ? 'Mesa' : 'Inscripción'}
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 bg-indigo-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold">Nueva {view === 'schedule' ? 'Mesa de Examen' : 'Inscripción'}</h3>
              <button onClick={() => setIsModalOpen(false)}><X /></button>
            </div>

            <form onSubmit={view === 'schedule' ? handleAddExam : handleAddEnrollment} className="p-8 space-y-4">
              {view === 'schedule' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Materia (Código)</label>
                    <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={examData.subjectId} onChange={e => setExamData({...examData, subjectId: e.target.value})} placeholder="Ej: MAT01" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Tipo</label>
                      <select className="w-full p-3 bg-slate-50 border rounded-xl" value={examData.type} onChange={e => setExamData({...examData, type: e.target.value as any})}>
                        <option>Parcial</option>
                        <option>Final</option>
                        <option>Libre</option>
                      </select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Lugar</label>
                      <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={examData.location} onChange={e => setExamData({...examData, location: e.target.value})} placeholder="Aula 101" />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Fecha y Hora</label>
                    <input required type="datetime-local" className="w-full p-3 bg-slate-50 border rounded-xl" value={examData.date} onChange={e => setExamData({...examData, date: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Cierre de Inscripción</label>
                    <input required type="datetime-local" className="w-full p-3 bg-slate-50 border rounded-xl" value={examData.closingDate} onChange={e => setExamData({...examData, closingDate: e.target.value})} />
                  </div>
                </>
              ) : (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Alumno</label>
                    <select required className="w-full p-3 bg-slate-50 border rounded-xl" value={enrollmentData.studentId} onChange={e => setEnrollmentData({...enrollmentData, studentId: e.target.value})}>
                      <option value="">Seleccionar...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.firstName} {s.lastName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Examen / Mesa</label>
                    <select required className="w-full p-3 bg-slate-50 border rounded-xl" value={enrollmentData.examId} onChange={e => setEnrollmentData({...enrollmentData, examId: e.target.value})}>
                      <option value="">Seleccionar...</option>
                      {exams.map(ex => <option key={ex.id} value={ex.id}>{ex.subjectId} - {ex.type} ({new Date(ex.date).toLocaleDateString()})</option>)}
                    </select>
                  </div>
                </>
              )}

              <button disabled={loading} className="w-full p-4 bg-indigo-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 mt-4">
                {loading ? <Loader2 className="animate-spin" /> : <Save size={20} />} Guardar {view === 'schedule' ? 'Examen' : 'Inscripción'}
              </button>
            </form>
          </div>
        </div>
      )}

      {view === 'enrollment' && (
        <div className="bg-amber-50 border border-amber-100 p-6 rounded-xl space-y-2 shadow-sm shadow-amber-50">
          <div className="flex items-center gap-2 text-amber-800 font-bold text-xs uppercase">
            <AlertTriangle size={16} /> Restricciones de inscripción
          </div>
          <ul className="text-xs text-amber-700 font-semibold space-y-1.5 list-disc ml-5">
            <li>Los alumnos con <span className="font-bold underline">cuotas vencidas</span> (vencimiento día 10 de cada mes) no pueden inscribirse</li>
            <li>La inscripción cierra <span className="font-bold">48 horas antes</span> del examen</li>
            <li>Deben tener aprobadas las <span className="font-bold underline">materias correlativas</span></li>
          </ul>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#F8FAFC] border-b border-slate-100">
            <tr>
              {view === 'schedule' ? (
                <>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Materia</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Tipo</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Fecha/Hora</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Lugar</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Estado</th>
                </>
              ) : (
                <>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Alumno</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Examen</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Fecha Inscripción</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Estado</th>
                </>
              )}
              <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm">
            {view === 'schedule' ? (
              exams.length > 0 ? exams.map(e => (
                <tr key={e.id} className="hover:bg-slate-50/50">
                  <td className="px-6 py-4 font-bold text-slate-800">{e.subjectId}</td>
                  <td className="px-6 py-4 text-center text-slate-600 font-medium">{e.type}</td>
                  <td className="px-6 py-4 text-center text-slate-600">{new Date(e.date).toLocaleString()}</td>
                  <td className="px-6 py-4 text-center text-slate-500">{e.location}</td>
                  <td className="px-6 py-4 text-center"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg font-bold text-[10px] uppercase">{e.status}</span></td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button onClick={() => handleDelete('exams', e.id)} className="p-2 text-rose-300 hover:text-rose-600"><Trash2 size={16} /></button>
                    <button className="p-2 text-slate-300 hover:text-indigo-600"><Edit3 size={16} /></button>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan={6} className="py-20 text-center text-slate-400 italic">No hay exámenes programados</td></tr>
              )
            ) : (
              enrollments.length > 0 ? enrollments.map(en => (
                <tr key={en.id} className="hover:bg-slate-50/50">
                  <td className="px-6 py-4 font-bold text-slate-800">{getStudentName(en.studentId)}</td>
                  <td className="px-6 py-4 text-center text-slate-600 font-medium">{getExamSubject(en.examId)}</td>
                  <td className="px-6 py-4 text-center text-slate-500">{new Date(en.date).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-center"><span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg font-bold text-[10px] uppercase">{en.status}</span></td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => handleDelete('enrollments', en.id)} className="p-2 text-rose-300 hover:text-rose-600"><Trash2 size={16} /></button>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan={5} className="py-20 text-center text-slate-400 italic">No hay inscripciones registradas</td></tr>
              )
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

