import React, { useState } from 'react';
import { UserPlus, ArrowLeft, Save, Plus, Trash2, Loader2, CheckCircle2, UserCheck } from 'lucide-react';
import { AcademicLevel, Student } from '../types';
import { supabase } from '../supabaseClient';

interface Tutor {
  id: string;
  name: string;
  phone: string;
  email?: string;
}

interface NewStudentFormProps {
  onCancel: () => void;
  onSave: () => void;
}

const NewStudentForm: React.FC<NewStudentFormProps> = ({ onCancel, onSave }) => {
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [tutors, setTutors] = useState<Tutor[]>([{ id: '1', name: '', phone: '' }]);

  const [formData, setFormData] = useState({
    dni: '',
    birthDate: '',
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    address: '',
    level: AcademicLevel.INITIAL,
    grade: '',
    division: '',
    enrollmentDate: new Date().toISOString().split('T')[0],
    status: 'ACTIVE' as 'ACTIVE' | 'INACTIVE'
  });

  const handleAddTutor = () => {
    setTutors([...tutors, { id: Math.random().toString(36).substr(2, 9), name: '', phone: '' }]);
  };

  const handleRemoveTutor = (id: string) => {
    if (tutors.length > 1) {
      setTutors(tutors.filter(t => t.id !== id));
    }
  };

  const handleTutorChange = (id: string, field: keyof Tutor, value: string) => {
    setTutors(tutors.map(t => t.id === id ? { ...t, [field]: value } : t));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.dni || !formData.firstName || !formData.lastName) {
      alert('Por favor complete los campos obligatorios del alumno.');
      return;
    }

    setLoading(true);

    try {
      const studentPayload: Partial<Student> = {
        ...formData,
        school_id: 'school-1',
        careerIds: [],
        tutorName: tutors.map(t => t.name).filter(Boolean).join(' | '),
        tutorPhone: tutors.map(t => t.phone).filter(Boolean).join(' | ')
      };

      await supabase.from('students').insert(studentPayload);
      setSuccess(true);
      setTimeout(() => {
        onSave();
      }, 1500);
    } catch (err) {
      console.error(err);
      alert('Error al guardar el alumno.');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center animate-in zoom-in-95 duration-300">
        <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-6 shadow-xl shadow-emerald-50">
          <UserCheck size={40} />
        </div>
        <h2 className="text-3xl font-black text-slate-800">¡Alumno Registrado!</h2>
        <p className="text-slate-500 mt-2 font-medium">La matriculación se ha procesado con éxito.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-300 pb-20 max-w-5xl mx-auto">
      <div className="flex items-center gap-4">
        <button onClick={onCancel} className="p-3 bg-white border border-slate-100 text-slate-400 hover:text-slate-800 transition-all rounded-2xl shadow-sm hover:shadow-md">
          <ArrowLeft size={20} />
        </button>
        <div className="flex items-center gap-3">
          <div className="text-indigo-600 bg-indigo-50 p-2.5 rounded-2xl">
            <UserPlus size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-[#1E293B] tracking-tight">Nuevo Alumno</h2>
            <p className="text-sm text-slate-400 font-bold uppercase tracking-wide">Completa los datos para matricular un nuevo alumno</p>
          </div>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        {/* Datos Personales */}
        <section className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-100 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600"></div>
          <h3 className="text-lg font-black text-[#1E293B] mb-8 flex items-center gap-2">
            <span className="w-8 h-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center text-sm">1</span>
            Datos Personales
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">DNI *</label>
              <input required value={formData.dni} onChange={e => setFormData({...formData, dni: e.target.value.replace(/\D/g, '')})} placeholder="12345678" className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-indigo-50 focus:border-indigo-600 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Fecha de Nacimiento</label>
              <input type="date" value={formData.birthDate} onChange={e => setFormData({...formData, birthDate: e.target.value})} className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-indigo-50 focus:border-indigo-600 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Nombre *</label>
              <input required value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} placeholder="Juan" className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-indigo-50 focus:border-indigo-600 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Apellido *</label>
