              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Dirección Completa</label>
              <input value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} placeholder="Calle 123, Ciudad, CP" className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-indigo-50 focus:border-indigo-600 outline-none transition-all" />
