            <button type="button" onClick={handleAddTutor} className="text-xs bg-emerald-50 text-emerald-600 px-4 py-2 rounded-xl font-black flex items-center gap-2 hover:bg-emerald-100 transition-all uppercase tracking-widest shadow-sm shadow-emerald-50">
              <Plus size={16} /> Añadir Tutor
            </button>
          </div>

          <div className="space-y-8">
            {tutors.map((tutor, index) => (
              <div key={tutor.id} className="grid grid-cols-1 md:grid-cols-2 gap-8 p-8 rounded-3xl bg-slate-50/50 border border-slate-100 relative animate-in fade-in slide-in-from-top-2 duration-300">
                {tutors.length > 1 && (
                  <button type="button" onClick={() => handleRemoveTutor(tutor.id)} className="absolute -top-3 -right-3 p-2 bg-white border border-slate-200 text-rose-500 rounded-full hover:bg-rose-500 hover:text-white transition-all shadow-lg">
                    <Trash2 size={16} />
                  </button>
                )}
                <div className="space-y-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Nombre Completo (Tutor {index + 1})</label>
                  <input required value={tutor.name} onChange={e => handleTutorChange(tutor.id, 'name', e.target.value)} placeholder="Ej: María García" className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-emerald-50 focus:border-emerald-500 outline-none transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Teléfono Móvil (Tutor {index + 1})</label>
                  <input required value={tutor.phone} onChange={e => handleTutorChange(tutor.id, 'phone', e.target.value)} placeholder="+54 11 9876-5432" className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-semibold focus:ring-4 focus:ring-emerald-50 focus:border-emerald-500 outline-none transition-all" />
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Datos Académicos */}
        <section className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-100 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-2 h-full bg-amber-500"></div>
          <h3 className="text-lg font-black text-[#1E293B] mb-8 flex items-center gap-2">
            <span className="w-8 h-8 rounded-lg bg-amber-50 text-amber-600 flex items-center justify-center text-sm">3</span>
            Datos Académicos
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Nivel Educativo *</label>
              <select required value={formData.level} onChange={e => setFormData({...formData, level: e.target.value as AcademicLevel})} className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-bold focus:ring-4 focus:ring-amber-50 focus:border-amber-500 outline-none transition-all appearance-none">
                {Object.values(AcademicLevel).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Grado / Sala</label>
              <input value={formData.grade} onChange={e => setFormData({...formData, grade: e.target.value})} placeholder="Ej: 1° Año" className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-bold focus:ring-4 focus:ring-amber-50 focus:border-amber-500 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">División</label>
              <input value={formData.division} onChange={e => setFormData({...formData, division: e.target.value})} placeholder="A, B, C..." className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-bold focus:ring-4 focus:ring-amber-50 focus:border-amber-500 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Fecha Matriculación</label>
              <input type="date" value={formData.enrollmentDate} onChange={e => setFormData({...formData, enrollmentDate: e.target.value})} className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-bold focus:ring-4 focus:ring-amber-50 focus:border-amber-500 outline-none transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Estado Alumno</label>
              <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as any})} className="w-full bg-[#F8FAFC] border border-slate-200 rounded-2xl p-4 text-sm font-bold focus:ring-4 focus:ring-amber-50 focus:border-amber-500 outline-none transition-all appearance-none">
                <option value="ACTIVE">Activo / Inscripto</option>
                <option value="INACTIVE">Inactivo / Baja</option>
              </select>
            </div>
          </div>
        </section>

        <div className="flex justify-end gap-4 pt-8">
          <button type="button" onClick={onCancel} className="px-10 py-4.5 border border-slate-200 rounded-[1.5rem] text-slate-600 font-black hover:bg-slate-50 transition-all uppercase tracking-widest text-xs">Cancelar</button>
          <button 
            type="submit" 
            disabled={loading} 
            className="px-12 py-4.5 bg-indigo-600 text-white rounded-[1.5rem] font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 hover:-translate-y-1 transition-all flex items-center gap-3 uppercase tracking-widest text-xs"
          >
            {loading ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />} 
            Crear Alumno
          </button>
        </div>
      </form>
    </div>
  );
};

export default NewStudentForm;

import React, { useState } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, Info, GraduationCap, X, Loader2, Save } from 'lucide-react';
import { Subject, Career, Enrollment, AcademicLevel } from '../types';
// INITIAL_STUDENTS is a constant, not a type. It should be imported from constants.ts
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
  subjects: Subject[];
  careers: Career[];
  enrollments: Enrollment[];
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view, subjects: initialSubjects, careers: initialCareers, enrollments: initialEnrollments }) => {
  const [subjects, setSubjects] = useState<Subject[]>(initialSubjects);
  const [careers, setCareers] = useState<Career[]>(initialCareers);
  const [enrollments, setEnrollments] = useState<Enrollment[]>(initialEnrollments);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);

  const [subjectData, setSubjectData] = useState<Partial<Subject>>({
    code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4
  });
  const [careerData, setCareerData] = useState<Partial<Career>>({
    code: '', name: '', duration: '', description: '', status: 'active'
  });
  const [enrollmentData, setEnrollmentData] = useState<Partial<Enrollment>>({
    studentId: '', careerId: '', year: '2026', status: 'Activa'
  });

  const handleDelete = async (table: string, id: string) => {
    if (!confirm('¿Seguro que desea eliminar este registro?')) return;
    try {
      await supabase.from(table).delete().eq('id', id);
      if (table === 'subjects') setSubjects(subjects.filter(s => s.id !== id));
      if (table === 'careers') setCareers(careers.filter(c => c.id !== id));
      if (table === 'enrollments') setEnrollments(enrollments.filter(e => e.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddSubject = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...subjectData, id: `s-${Date.now()}`, school_id: 'school-1', prerequisites: [] };
    await supabase.from('subjects').insert(newItem);
    setSubjects([newItem as Subject, ...subjects]);
    setLoading(false);
    setIsModalOpen(false);
    setSubjectData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
  };

  const handleAddCareer = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...careerData, id: `c-${Date.now()}`, school_id: 'school-1' };
    await supabase.from('careers').insert(newItem);
    setCareers([newItem as Career, ...careers]);
    setLoading(false);
    setIsModalOpen(false);
    setCareerData({ code: '', name: '', duration: '', description: '', status: 'active' });
  };

  const handleAddEnrollment = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...enrollmentData, id: `en-${Date.now()}`, date: new Date().toISOString() };
    await supabase.from('enrollments').insert(newItem);
    setEnrollments([newItem as Enrollment, ...enrollments]);
    setLoading(false);
    setIsModalOpen(false);
    setEnrollmentData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
  };

  const getStudentName = (id: string) => {
    const s = initialSubjects.length ? INITIAL_STUDENTS.find(st => st.id === id) : null;
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno Desconocido';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera Desconocida';
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className={view === 'careers' ? 'text-[#10B981]' : 'text-indigo-600'}>
            {view === 'careers' ? <GraduationCap size={28} /> : <Book size={28} />}
          </div>
          <div>
            <h2 className="text-2xl font-bold text-[#1E293B]">
              {view === 'subjects' && 'Materias'}
              {view === 'careers' && 'Carreras (Terciario)'}
              {view === 'enrollments' && 'Inscripciones a Carreras'}
            </h2>
            <p className="text-xs text-slate-400 font-bold uppercase">
              {view === 'subjects' && 'Gestión de materias por nivel educativo'}
              {view === 'careers' && 'Gestión de carreras de nivel terciario'}
              {view === 'enrollments' && 'Gestión de inscripciones de alumnos terciarios a carreras'}
            </p>
          </div>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className={`${view === 'careers' ? 'bg-[#10B981]' : 'bg-indigo-600'} text-white px-5 py-2.5 rounded-xl flex items-center gap-2 font-bold shadow-lg`}
        >
          <Plus size={20} /> Nueva {view === 'subjects' ? 'Materia' : view === 'careers' ? 'Carrera' : 'Inscripción'}
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className={`p-6 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white flex justify-between items-center`}>
              <h3 className="text-xl font-bold">Nueva {view === 'subjects' ? 'Materia' : view === 'careers' ? 'Carrera' : 'Inscripción'}</h3>
              <button onClick={() => setIsModalOpen(false)}><X /></button>
            </div>

            <form onSubmit={view === 'subjects' ? handleAddSubject : view === 'careers' ? handleAddCareer : handleAddEnrollment} className="p-8 space-y-4">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Código</label>
                      <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={subjectData.code} onChange={e => setSubjectData({...subjectData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Horas/Sem</label>
                      <input required type="number" className="w-full p-3 bg-slate-50 border rounded-xl" value={subjectData.hoursPerWeek} onChange={e => setSubjectData({...subjectData, hoursPerWeek: parseInt(e.target.value)})} />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Nombre de la Materia</label>
                    <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={subjectData.name} onChange={e => setSubjectData({...subjectData, name: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Grado / Año</label>
                    <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={subjectData.grade} onChange={e => setSubjectData({...subjectData, grade: e.target.value})} placeholder="Ej: 1° Año" />
                  </div>
                </>
              )}

              {view === 'careers' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Código</label>
                      <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={careerData.code} onChange={e => setCareerData({...careerData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500">Duración</label>
                      <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={careerData.duration} onChange={e => setCareerData({...careerData, duration: e.target.value})} placeholder="Ej: 3 años" />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Nombre de la Carrera</label>
                    <input required className="w-full p-3 bg-slate-50 border rounded-xl" value={careerData.name} onChange={e => setCareerData({...careerData, name: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Descripción</label>
                    <textarea rows={3} className="w-full p-3 bg-slate-50 border rounded-xl" value={careerData.description} onChange={e => setCareerData({...careerData, description: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'enrollments' && (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Seleccionar Alumno</label>
                    <select required className="w-full p-3 bg-slate-50 border rounded-xl" value={enrollmentData.studentId} onChange={e => setEnrollmentData({...enrollmentData, studentId: e.target.value})}>
                      <option value="">Seleccionar...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.firstName} {s.lastName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Seleccionar Carrera</label>
                    <select required className="w-full p-3 bg-slate-50 border rounded-xl" value={enrollmentData.careerId} onChange={e => setEnrollmentData({...enrollmentData, careerId: e.target.value})}>
                      <option value="">Seleccionar...</option>
                      {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500">Año de Cursada</label>
                    <input className="w-full p-3 bg-slate-50 border rounded-xl" value={enrollmentData.year} onChange={e => setEnrollmentData({...enrollmentData, year: e.target.value})} />
                  </div>
                </>
              )}

              <button disabled={loading} className={`w-full p-4 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white rounded-2xl font-bold flex items-center justify-center gap-2`}>
                {loading ? <Loader2 className="animate-spin" /> : <Save size={20} />} Guardar {view === 'subjects' ? 'Materia' : view === 'careers' ? 'Carrera' : 'Inscripción'}
              </button>
            </form>
          </div>
        </div>
      )}

      {view !== 'enrollments' && (
        <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex gap-4 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input placeholder="Buscar por nombre o código..." className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none" />
          </div>
          <select className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-semibold outline-none min-w-[140px]">
            <option>Todos</option>
          </select>
        </div>
      )}

      {view === 'enrollments' && (
        <div className="bg-indigo-50/50 border border-indigo-100 p-4 rounded-xl flex items-center gap-3">
          <Info className="text-indigo-600" size={18} />
          <p className="text-xs text-indigo-700 font-semibold">Los alumnos de nivel terciario pueden inscribirse en hasta <span className="underline">2 carreras</span> simultáneamente.</p>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#F8FAFC] border-b border-slate-100">
            <tr>
              {view === 'subjects' && (
                <>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Código</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Nombre</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Nivel</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Grado/Año</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Hs/Sem</th>
                </>
              )}
              {view === 'careers' && (
                <>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Código</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Nombre</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Duración</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Estado</th>
                </>
              )}
              {view === 'enrollments' && (
                <>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider">Alumno</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Carrera</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Año Cursando</th>
                  <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-center">Estado</th>
                </>
              )}
              <th className="px-6 py-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm">
            {view === 'subjects' && subjects.map(s => (
              <tr key={s.id} className="hover:bg-slate-50/50">
                <td className="px-6 py-4 font-bold text-slate-500">{s.code}</td>
                <td className="px-6 py-4 font-bold text-slate-800">{s.name}</td>
                <td className="px-6 py-4 text-slate-600">{s.level}</td>
                <td className="px-6 py-4 text-slate-600">{s.grade}</td>
                <td className="px-6 py-4 text-center font-bold text-slate-600">{s.hoursPerWeek}</td>
                <td className="px-6 py-4 text-right space-x-2">
                  <button className="p-2 text-slate-400 hover:text-indigo-600"><Edit3 size={16} /></button>
                  <button onClick={() => handleDelete('subjects', s.id)} className="p-2 text-rose-400 hover:text-rose-600"><Trash2 size={16} /></button>
                </td>
              </tr>
            ))}
            {view === 'careers' && careers.map(c => (
              <tr key={c.id} className="hover:bg-slate-50/50">
                <td className="px-6 py-5 font-bold text-slate-500">{c.code}</td>
                <td className="px-6 py-5 font-bold text-slate-800">{c.name}</td>
                <td className="px-6 py-5 text-slate-600 flex items-center gap-2"><Clock size={14} /> {c.duration}</td>
                <td className="px-6 py-5 text-center"><span className="px-3 py-1 bg-emerald-100 text-emerald-600 rounded-full text-[10px] font-bold uppercase">activa</span></td>
