          <table className="w-full text-left">
            <thead className="bg-slate-50/80 border-b border-slate-100">
              <tr>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Alumno</th>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">DNI</th>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Curso</th>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Nivel</th>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Estado</th>
                <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {students.length > 0 ? students.map((student) => (
                <tr key={student.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-5">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-full bg-indigo-500 flex items-center justify-center text-white text-sm font-black shadow-sm`}>
                        {student.firstName[0]}{student.lastName[0]}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-base">{student.firstName} {student.lastName}</span>
                        <span className="text-sm text-slate-400 font-medium">{student.email}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    <span className="text-slate-500 font-bold text-base tracking-tight">{student.dni}</span>
                  </td>
                  <td className="px-6 py-5">
                    <span className="text-slate-600 font-bold text-base">{student.grade}</span>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`text-xs px-3 py-1.5 rounded-xl font-black uppercase ${getLevelBadgeStyles(student.level)}`}>
                      {student.level}
                    </span>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`inline-flex items-center px-3 py-1.5 rounded-xl text-xs font-black border ${student.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                      {student.status === 'ACTIVE' ? 'ACTIVO' : 'INACTIVO'}
                    </span>
                  </td>
                  <td className="px-6 py-5 text-right space-x-1">
                    <button 
                      onClick={() => alert(`Editar alumno: ${student.firstName} (Disponible en versión Pro)`)}
                      className="p-2.5 text-slate-400 hover:text-indigo-600 transition-all rounded-xl hover:bg-indigo-50"
                    >
                      <Edit3 size={18} />
                    </button>
                    <button 
                      onClick={() => handleDeleteStudent(student.id)}
                      className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={6} className="py-20 text-center text-slate-400 font-medium">
                    No se encontraron alumnos registrados.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="px-6 py-5 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
          <p className="text-base text-slate-500 font-medium">Mostrando {students.length} de {count} alumnos</p>
          <div className="flex gap-2">
            <button 
              disabled={page === 0}
              onClick={() => setPage(page - 1)}
              className="px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-bold disabled:opacity-50 hover:bg-slate-50 transition-all"
            >
              Anterior
            </button>
            <button 
              disabled={(page + 1) * 25 >= count}
              onClick={() => setPage(page + 1)}
              className="px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-bold disabled:opacity-50 hover:bg-slate-50 transition-all"
            >
              Siguiente
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentsModule;

import React, { useState } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, Info, GraduationCap, X, Loader2, Save } from 'lucide-react';
import { Subject, Career, Enrollment, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
  subjects: Subject[];
  careers: Career[];
  enrollments: Enrollment[];
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view, subjects: initialSubjects, careers: initialCareers, enrollments: initialEnrollments }) => {
  const [subjects, setSubjects] = useState<Subject[]>(initialSubjects);
  const [careers, setCareers] = useState<Career[]>(initialCareers);
  const [enrollments, setEnrollments] = useState<Enrollment[]>(initialEnrollments);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [subjectData, setSubjectData] = useState<Partial<Subject>>({
    code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4
  });
  const [careerData, setCareerData] = useState<Partial<Career>>({
    code: '', name: '', duration: '', description: '', status: 'active'
  });
  const [enrollmentData, setEnrollmentData] = useState<Partial<Enrollment>>({
    studentId: '', careerId: '', year: '2026', status: 'Activa'
  });

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setSubjectData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
    setCareerData({ code: '', name: '', duration: '', description: '', status: 'active' });
    setEnrollmentData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
  };

  const openEdit = (type: string, item: any) => {
    setEditingId(item.id);
    if (type === 'subjects') setSubjectData(item);
    if (type === 'careers') setCareerData(item);
    setIsModalOpen(true);
  };

  const handleDelete = async (table: string, id: string) => {
    if (!confirm('¿Seguro que desea eliminar este registro?')) return;
    try {
      await supabase.from(table).delete().eq('id', id);
      if (table === 'subjects') setSubjects(subjects.filter(s => s.id !== id));
      if (table === 'careers') setCareers(careers.filter(c => c.id !== id));
      if (table === 'enrollments') setEnrollments(enrollments.filter(e => e.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleSaveSubject = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    if (editingId) {
      await supabase.from('subjects').update(subjectData).eq('id', editingId);
      setSubjects(subjects.map(s => s.id === editingId ? { ...s, ...subjectData } : s));
    } else {
      const newItem = { ...subjectData, id: `s-${Date.now()}`, school_id: 'school-1', prerequisites: [] };
      await supabase.from('subjects').insert(newItem);
      setSubjects([newItem as Subject, ...subjects]);
    }
    setLoading(false);
    resetForms();
  };

  const handleSaveCareer = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    if (editingId) {
      await supabase.from('careers').update(careerData).eq('id', editingId);
      setCareers(careers.map(c => c.id === editingId ? { ...c, ...careerData } : c));
    } else {
      const newItem = { ...careerData, id: `c-${Date.now()}`, school_id: 'school-1' };
      await supabase.from('careers').insert(newItem);
      setCareers([newItem as Career, ...careers]);
    }
    setLoading(false);
    resetForms();
  };

  const handleAddEnrollment = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...enrollmentData, id: `en-${Date.now()}`, date: new Date().toISOString() };
    await supabase.from('enrollments').insert(newItem);
    setEnrollments([newItem as Enrollment, ...enrollments]);
    setLoading(false);
    resetForms();
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera';
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className={`${view === 'careers' ? 'text-[#10B981] bg-emerald-50' : 'text-indigo-600 bg-indigo-50'} p-3 rounded-2xl`}>
            {view === 'careers' ? <GraduationCap size={32} /> : <Book size={32} />}
          </div>
          <div>
            <h2 className="text-3xl font-black text-[#1E293B] tracking-tight">
              {view === 'subjects' && 'Materias'}
              {view === 'careers' && 'Carreras (Terciario)'}
              {view === 'enrollments' && 'Inscripciones a Carreras'}
            </h2>
            <p className="text-base text-slate-500 mt-1 font-medium">
              {view === 'subjects' && 'Gestión de materias por nivel educativo'}
              {view === 'careers' && 'Gestión de carreras de nivel terciario'}
              {view === 'enrollments' && 'Gestión de inscripciones de alumnos terciarios'}
            </p>
          </div>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className={`${view === 'careers' ? 'bg-[#10B981]' : 'bg-indigo-600'} text-white px-6 py-3 rounded-xl flex items-center gap-2 font-black shadow-lg text-sm uppercase tracking-widest`}
        >
          <Plus size={20} /> Nueva {view === 'subjects' ? 'Materia' : view === 'careers' ? 'Carrera' : 'Inscripción'}
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className={`p-6 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white flex justify-between items-center`}>
              <h3 className="text-xl font-black uppercase tracking-tight">{editingId ? 'Editar' : 'Nueva'} {view === 'subjects' ? 'Materia' : view === 'careers' ? 'Carrera' : 'Inscripción'}</h3>
              <button onClick={resetForms}><X /></button>
            </div>

            <form onSubmit={view === 'subjects' ? handleSaveSubject : view === 'careers' ? handleSaveCareer : handleAddEnrollment} className="p-8 space-y-5">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Código</label>
                      <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={subjectData.code} onChange={e => setSubjectData({...subjectData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Horas/Sem</label>
                      <input required type="number" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={subjectData.hoursPerWeek} onChange={e => setSubjectData({...subjectData, hoursPerWeek: parseInt(e.target.value)})} />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Nombre de la Materia</label>
                    <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={subjectData.name} onChange={e => setSubjectData({...subjectData, name: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Grado / Año</label>
                    <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={subjectData.grade} onChange={e => setSubjectData({...subjectData, grade: e.target.value})} placeholder="Ej: 1° Año" />
                  </div>
                </>
              )}

              {view === 'careers' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Código</label>
                      <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-600 outline-none transition-all font-bold" value={careerData.code} onChange={e => setCareerData({...careerData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Duración</label>
                      <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-600 outline-none transition-all font-bold" value={careerData.duration} onChange={e => setCareerData({...careerData, duration: e.target.value})} placeholder="Ej: 3 años" />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Nombre de la Carrera</label>
                    <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-600 outline-none transition-all font-bold" value={careerData.name} onChange={e => setCareerData({...careerData, name: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Descripción</label>
                    <textarea rows={3} className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-600 outline-none transition-all font-bold" value={careerData.description} onChange={e => setCareerData({...careerData, description: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'enrollments' && (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Alumno</label>
                    <select required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={enrollmentData.studentId} onChange={e => setEnrollmentData({...enrollmentData, studentId: e.target.value})}>
                      <option value="">Seleccionar alumno...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.firstName} {s.lastName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Carrera</label>
                    <select required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" value={enrollmentData.careerId} onChange={e => setEnrollmentData({...enrollmentData, careerId: e.target.value})}>
                      <option value="">Seleccionar carrera...</option>
                      {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                </>
              )}

              <button disabled={loading} className={`w-full p-5 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white rounded-[1.5rem] font-black uppercase tracking-widest text-sm shadow-xl flex items-center justify-center gap-2 hover:-translate-y-1 transition-all`}>
                {loading ? <Loader2 className="animate-spin" /> : <Save size={18} />} Guardar Cambios
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex gap-4 items-center">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
          <input placeholder="Buscar por nombre o código..." className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border-2 border-slate-100 rounded-2xl text-base font-medium outline-none" />
        </div>
        <select className="bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-3.5 text-sm font-black uppercase tracking-wider outline-none min-w-[140px]">
          <option>Todos</option>
        </select>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#F8FAFC] border-b border-slate-100">
            <tr>
              {view === 'subjects' && (
                <>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Código</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Nombre</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Nivel</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Grado/Año</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Hs/Sem</th>
                </>
              )}
              {view === 'careers' && (
                <>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Código</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Nombre</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Duración</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Estado</th>
                </>
              )}
              {view === 'enrollments' && (
                <>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Alumno</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Carrera</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Año</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Estado</th>
                </>
              )}
              <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-base font-medium">
            {view === 'subjects' && subjects.map(s => (
              <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-5 font-bold text-slate-500">{s.code}</td>
                <td className="px-6 py-5 font-black text-slate-800">{s.name}</td>
                <td className="px-6 py-5 text-slate-600 font-bold">{s.level}</td>
                <td className="px-6 py-5 text-slate-600 font-bold">{s.grade}</td>
                <td className="px-6 py-5 text-center font-black text-slate-800">{s.hoursPerWeek}</td>
                <td className="px-6 py-5 text-right space-x-1">
                  <button onClick={() => openEdit('subjects', s)} className="p-2.5 text-slate-400 hover:text-indigo-600 transition-all rounded-xl hover:bg-indigo-50"><Edit3 size={18} /></button>
                  <button onClick={() => handleDelete('subjects', s.id)} className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"><Trash2 size={18} /></button>
                </td>
              </tr>
            ))}
            {view === 'careers' && careers.map(c => (
              <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-5 font-bold text-slate-500">{c.code}</td>
                <td className="px-6 py-5 font-black text-slate-800">{c.name}</td>
                <td className="px-6 py-5 text-slate-600 flex items-center gap-2 font-bold"><Clock size={16} /> {c.duration}</td>
                <td className="px-6 py-5 text-center"><span className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-xl text-xs font-black uppercase">activa</span></td>
                <td className="px-6 py-5 text-right space-x-1">
                  <button onClick={() => openEdit('careers', c)} className="p-2.5 text-slate-400 hover:text-emerald-600 transition-all rounded-xl hover:bg-emerald-50"><Edit3 size={18} /></button>
                  <button onClick={() => handleDelete('careers', c.id)} className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"><Trash2 size={18} /></button>
                </td>
              </tr>
            ))}
            {view === 'enrollments' && enrollments.map(e => (
              <tr key={e.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-5 font-black text-slate-800">{getStudentName(e.studentId)}</td>
                <td className="px-6 py-5 text-center text-slate-600 font-bold">{getCareerName(e.careerId)}</td>
                <td className="px-6 py-5 text-center text-slate-600 font-black">{e.year}</td>
                <td className="px-6 py-5 text-center"><span className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-xl text-xs font-black uppercase">{e.status}</span></td>
                <td className="px-6 py-5 text-right">
                  <button onClick={() => handleDelete('enrollments', e.id)} className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"><Trash2 size={18} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AcademicModule;

import React, { useState } from 'react';
import { ClipboardList, Plus, AlertTriangle, Trash2, X, Loader2, Save, Edit3 } from 'lucide-react';
import { Exam } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface ExamsModuleProps {
  view: 'schedule' | 'enrollment';
  exams: Exam[];
}

const ExamsModule: React.FC<ExamsModuleProps> = ({ view, exams: initialExams }) => {
  const [exams, setExams] = useState<Exam[]>(initialExams);
  const [enrollments, setEnrollments] = useState<any[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [examData, setExamData] = useState<Partial<Exam>>({
    subjectId: '', type: 'Parcial', date: '', closingDate: '', location: '', status: 'Programado'
  });

  const [enrollmentData, setEnrollmentData] = useState({
    studentId: '', examId: '', status: 'Inscripto'
  });

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setExamData({ subjectId: '', type: 'Parcial', date: '', closingDate: '', location: '', status: 'Programado' });
    setEnrollmentData({ studentId: '', examId: '', status: 'Inscripto' });
  };

  const handleSaveExam = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    if (editingId) {
      await supabase.from('exams').update(examData).eq('id', editingId);
      setExams(exams.map(ex => ex.id === editingId ? { ...ex, ...examData } as Exam : ex));
    } else {
      const newItem = { ...examData, id: `e-${Date.now()}` };
      await supabase.from('exams').insert(newItem);
      setExams([newItem as Exam, ...exams]);
    }
    setLoading(false);
    resetForms();
  };

  const openEditExam = (exam: Exam) => {
    setEditingId(exam.id);
    setExamData(exam);
    setIsModalOpen(true);
  };

  const handleAddEnrollment = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newItem = { ...enrollmentData, id: `ere-${Date.now()}`, date: new Date().toISOString() };
    await supabase.from('enrollments').insert(newItem);
    setEnrollments([newItem, ...enrollments]);
    setLoading(false);
    resetForms();
  };

  const handleDelete = async (table: string, id: string) => {
    if (!confirm('¿Seguro que desea eliminar este registro?')) return;
    await supabase.from(table).delete().eq('id', id);
    if (table === 'exams') setExams(exams.filter(e => e.id !== id));
    if (table === 'enrollments') setEnrollments(enrollments.filter(e => e.id !== id));
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno';
  };

  const getExamSubject = (id: string) => {
    const ex = exams.find(e => e.id === id);
    return ex ? ex.subjectId : 'Examen';
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className="text-indigo-600 bg-indigo-50 p-3 rounded-2xl">
            <ClipboardList size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-[#1E293B] tracking-tight">
              {view === 'schedule' ? 'Mesa de Exámenes' : 'Inscripciones a Exámenes'}
            </h2>
            <p className="text-base text-slate-500 mt-1 font-medium">
              {view === 'schedule' ? 'Programación de mesas y tribunales' : 'Gestión de inscripciones de alumnos'}
            </p>
          </div>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-black uppercase tracking-widest text-sm shadow-lg"
        >
          <Plus size={20} /> Nueva {view === 'schedule' ? 'Mesa' : 'Inscripción'}
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 bg-indigo-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-black uppercase tracking-tight">{editingId ? 'Editar' : 'Nueva'} {view === 'schedule' ? 'Mesa' : 'Inscripción'}</h3>
              <button onClick={resetForms}><X /></button>
            </div>

            <form onSubmit={view === 'schedule' ? handleSaveExam : handleAddEnrollment} className="p-8 space-y-5">
              {view === 'schedule' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Materia (Código)</label>
                    <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={examData.subjectId} onChange={e => setExamData({...examData, subjectId: e.target.value})} placeholder="Ej: MAT01" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Tipo</label>
                      <select className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={examData.type} onChange={e => setExamData({...examData, type: e.target.value as any})}>
                        <option>Parcial</option>
                        <option>Final</option>
                        <option>Libre</option>
                      </select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Lugar</label>
                      <input required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={examData.location} onChange={e => setExamData({...examData, location: e.target.value})} placeholder="Aula 101" />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Fecha y Hora</label>
                    <input required type="datetime-local" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={examData.date} onChange={e => setExamData({...examData, date: e.target.value})} />
                  </div>
                </>
              ) : (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Alumno</label>
                    <select required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={enrollmentData.studentId} onChange={e => setEnrollmentData({...enrollmentData, studentId: e.target.value})}>
                      <option value="">Seleccionar alumno...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.firstName} {s.lastName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Examen / Mesa</label>
                    <select required className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-600 transition-all font-bold" value={enrollmentData.examId} onChange={e => setEnrollmentData({...enrollmentData, examId: e.target.value})}>
                      <option value="">Seleccionar mesa...</option>
                      {exams.map(ex => <option key={ex.id} value={ex.id}>{ex.subjectId} - {ex.type}</option>)}
                    </select>
                  </div>
                </>
              )}

              <button disabled={loading} className="w-full p-5 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-widest text-sm shadow-xl flex items-center justify-center gap-2 hover:-translate-y-1 transition-all">
                {loading ? <Loader2 className="animate-spin" /> : <Save size={18} />} Guardar Datos
              </button>
            </form>
          </div>
        </div>
      )}

      {view === 'enrollment' && (
        <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl space-y-2 shadow-sm shadow-amber-50">
          <div className="flex items-center gap-2 text-amber-800 font-black text-xs uppercase tracking-widest">
            <AlertTriangle size={18} /> Restricciones de inscripción
          </div>
          <ul className="text-sm text-amber-700 font-bold space-y-1.5 list-disc ml-6">
            <li>Alumnos con <span className="underline">cuotas vencidas</span> al día 10 no pueden inscribirse.</li>
            <li>Inscripción cierra <span className="font-black underline">48 horas antes</span> del examen.</li>
          </ul>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#F8FAFC] border-b border-slate-100">
            <tr>
              {view === 'schedule' ? (
                <>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Materia</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Tipo</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Fecha/Hora</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Lugar</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Estado</th>
                </>
              ) : (
                <>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest">Alumno</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Examen</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Inscripto</th>
                  <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-center">Estado</th>
                </>
              )}
              <th className="px-6 py-5 text-sm font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-base font-medium">
            {view === 'schedule' ? (
              exams.length > 0 ? exams.map(e => (
                <tr key={e.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-5 font-black text-slate-800">{e.subjectId}</td>
                  <td className="px-6 py-5 text-center text-slate-600 font-bold">{e.type}</td>
                  <td className="px-6 py-5 text-center text-slate-600 font-bold">{new Date(e.date).toLocaleString([], { dateStyle: 'short', timeStyle: 'short' })}</td>
                  <td className="px-6 py-5 text-center text-slate-500 font-bold">{e.location}</td>
                  <td className="px-6 py-5 text-center"><span className="px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-xl font-black text-xs uppercase tracking-wider">{e.status}</span></td>
                  <td className="px-6 py-5 text-right space-x-1">
                    <button onClick={() => openEditExam(e)} className="p-2.5 text-slate-400 hover:text-indigo-600 transition-all rounded-xl hover:bg-indigo-50"><Edit3 size={18} /></button>
                    <button onClick={() => handleDelete('exams', e.id)} className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"><Trash2 size={18} /></button>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan={6} className="py-20 text-center text-slate-400 italic">No hay exámenes programados</td></tr>
              )
            ) : (
              enrollments.length > 0 ? enrollments.map(en => (
                <tr key={en.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-5 font-black text-slate-800">{getStudentName(en.studentId)}</td>
                  <td className="px-6 py-5 text-center text-slate-600 font-bold">{getExamSubject(en.examId)}</td>
                  <td className="px-6 py-5 text-center text-slate-500 font-bold">{new Date(en.date).toLocaleDateString()}</td>
                  <td className="px-6 py-5 text-center"><span className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-xl font-black text-xs uppercase tracking-wider">{en.status}</span></td>
                  <td className="px-6 py-5 text-right">
                    <button onClick={() => handleDelete('enrollments', en.id)} className="p-2.5 text-rose-300 hover:text-rose-600 transition-all rounded-xl hover:bg-rose-50"><Trash2 size={18} /></button>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan={5} className="py-20 text-center text-slate-400 italic">No hay inscripciones registradas</td></tr>
              )
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ExamsModule;

import React, { Suspense, useState } from 'react';
import { AuthProvider, useAuth } from './authContext';
import Layout from './components/Layout';
import Dashboard from './Dashboard';
import StudentsModule from './components/StudentsModule';
import AcademicModule from './components/AcademicModule';
import ExamsModule from './components/ExamsModule';
import BillingModule from './components/BillingModule';
import NewStudentForm from './components/NewStudentForm';
import { INITIAL_PAYMENTS } from './constants';
import { ShieldAlert, Loader2, ShieldCheck } from 'lucide-react';
import { supabase } from './supabaseClient';
import { Student } from './types';

const LoginForm = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const handleLogin = async (e?: any, demoEmail?: string) => {
    if (e) e.preventDefault();
    setLoading(true);
    await supabase.auth.signInWithOtp({ email: demoEmail || email });
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="max-w-md w-full bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-100">
        <div className="bg-indigo-600 p-10 text-center text-white">
           <h1 className="text-2xl font-black tracking-tight">EduManager Pro</h1>
           <p className="text-indigo-100 font-bold text-xs mt-1 uppercase tracking-widest opacity-80">Gestión Institucional</p>
        </div>
        <div className="p-8 space-y-6">
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="email" 
              placeholder="correo@ejemplo.com" 
              value={email} 
              onChange={e => setEmail(e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button className="w-full bg-indigo-600 text-white p-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2">
              {loading ? <Loader2 className="animate-spin" /> : 'Entrar'}
            </button>
          </form>
          <div className="relative flex items-center"><span className="flex-1 border-t border-slate-100"></span><span className="mx-4 text-[10px] font-black text-slate-300 uppercase">Prueba el sistema</span><span className="flex-1 border-t border-slate-100"></span></div>
          <button onClick={() => handleLogin(null, 'superadmin@edumanager.pro')} className="w-full bg-slate-800 text-white p-4 rounded-xl font-bold hover:bg-slate-900 transition-all flex items-center justify-center gap-2">
            <ShieldCheck size={18} /> Acceso Demo Superadmin
          </button>
        </div>
      </div>
    </div>
  );
};

const AppContent = () => {
  const { user, profile, loading, signOut } = useAuth();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [editingStudent, setEditingStudent] = useState<Student | null>(null);

  if (loading) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin text-indigo-600" size={40} /></div>;
  if (!user) return <LoginForm />;
  if (!profile) return <div className="p-20 text-center"><ShieldAlert className="mx-auto text-rose-500" size={64} /><h2 className="text-xl font-bold mt-4">Perfil no encontrado</h2><button onClick={signOut} className="text-indigo-600 font-bold mt-4 underline">Cerrar Sesión</button></div>;

  const handleEditStudent = (student: Student) => {
    setEditingStudent(student);
    setActiveTab('new-student');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard schoolId={profile.school_id} />;
      case 'students-list': return <StudentsModule schoolId={profile.school_id} onEditStudent={handleEditStudent} />;
      case 'new-student': return (
        <NewStudentForm 
          initialData={editingStudent || undefined}
          onCancel={() => { setEditingStudent(null); setActiveTab('students-list'); }} 
          onSave={() => { setEditingStudent(null); setActiveTab('students-list'); }} 
        />
      );
      case 'subjects': return <AcademicModule key="subjects" view="subjects" />;
      case 'careers': return <AcademicModule key="careers" view="careers" />;
      case 'enrollments': return <AcademicModule key="enrollments" view="enrollments" />;
      case 'exams-schedule': return <ExamsModule key="exams" view="schedule" />;
      case 'exams-enroll': return <ExamsModule key="exams-e" view="enrollment" />;
      case 'fees': return <BillingModule view="fees" payments={INITIAL_PAYMENTS} />;
      case 'billing-config': return <BillingModule view="config" payments={[]} />;
      default: return <Dashboard schoolId={profile.school_id} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={profile.role} 
      userName={profile.full_name} 
      onLogout={signOut}
    >
      <Suspense fallback={<div className="p-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={40} /></div>}>
        {renderContent()}
      </Suspense>
    </Layout>
  );
};

const App = () => (
  <AuthProvider>
    <AppContent />
  </AuthProvider>
);

export default App;

