import React, { useState, useEffect } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, GraduationCap, X, Loader2, Save } from 'lucide-react';
import { Subject, Career, Enrollment, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view }) => {
  const [dataList, setDataList] = useState<any[]>([]);
  const [careers, setCareers] = useState<Career[]>([]); // Necesario para el dropdown de inscripciones
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [btnLoading, setBtnLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<any>({});

  const tableMap = {
    subjects: 'subjects',
    careers: 'careers',
    enrollments: 'enrollments'
  };

  useEffect(() => {
    fetchData();
    if (view === 'enrollments') fetchCareers();
  }, [view]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from(tableMap[view]).select('*');
    setDataList(data || []);
    setLoading(false);
  };

  const fetchCareers = async () => {
    const { data } = await supabase.from('careers').select('*');
    setCareers(data || []);
  };

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openNew = () => {
    if (view === 'subjects') setFormData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
    if (view === 'careers') setFormData({ code: '', name: '', duration: '', description: '', status: 'active' });
    if (view === 'enrollments') setFormData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
    setIsModalOpen(true);
  };

  const openEdit = (item: any) => {
    setEditingId(item.id);
    setFormData(item);
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Seguro que desea eliminar este registro?')) return;
    await supabase.from(tableMap[view]).delete().eq('id', id);
    setDataList(prev => prev.filter(i => i.id !== id));
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setBtnLoading(true);
    try {
      if (editingId) {
        await supabase.from(tableMap[view]).update(formData).eq('id', editingId);
      } else {
        const newItem = { ...formData, school_id: 'school-1' };
        await supabase.from(tableMap[view]).insert(newItem);
      }
      await fetchData();
      resetForms();
    } catch (err) {
      console.error(err);
    } finally {
      setBtnLoading(false);
    }
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera';
  };

  return (
    <div className="space-y-5 animate-in fade-in duration-300">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className={`${view === 'careers' ? 'text-emerald-600 bg-emerald-50' : 'text-indigo-600 bg-indigo-50'} p-2.5 rounded-xl`}>
            {view === 'careers' ? <GraduationCap size={28} /> : <Book size={28} />}
