        >
          <Plus size={18} /> Nuevo
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className={`p-5 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white flex justify-between items-center`}>
              <h3 className="text-sm font-black uppercase tracking-widest">{editingId ? 'Editar' : 'Nuevo'} Registro</h3>
              <button onClick={resetForms}><X size={20} /></button>
            </div>

            <form onSubmit={handleSave} className="p-7 space-y-4">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Código</label>
                      <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-indigo-600 outline-none text-sm font-bold" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Hs/Sem</label>
                      <input required type="number" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-indigo-600 outline-none text-sm font-bold" value={formData.hoursPerWeek} onChange={e => setFormData({...formData, hoursPerWeek: e.target.value})} />
