                      <option value="">Seleccionar...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.firstName} {s.lastName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Carrera</label>
                    <select required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm font-bold" value={formData.careerId} onChange={e => setFormData({...formData, careerId: e.target.value})}>
                      <option value="">Seleccionar...</option>
                      {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                </>
              )}

              <button disabled={btnLoading} className={`w-full p-4 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-lg flex items-center justify-center gap-2 mt-2`}>
