import React, { useState, useEffect } from 'react';
import { UserPlus, ArrowLeft, Save, Plus, Trash2, Loader2, UserCheck } from 'lucide-react';
import { AcademicLevel, Student } from '../types';
import { supabase } from '../supabaseClient';

interface Tutor {
  id: string;
  name: string;
  phone: string;
  email?: string;
}

interface NewStudentFormProps {
  initialData?: Student;
  onCancel: () => void;
  onSave: () => void;
}

const NewStudentForm: React.FC<NewStudentFormProps> = ({ initialData, onCancel, onSave }) => {
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [tutors, setTutors] = useState<Tutor[]>([{ id: '1', name: '', phone: '' }]);

  const [formData, setFormData] = useState({
    dni: '',
    birthDate: '',
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    address: '',
    level: AcademicLevel.INITIAL,
    grade: '',
    division: '',
    enrollmentDate: new Date().toISOString().split('T')[0],
    status: 'ACTIVE' as 'ACTIVE' | 'INACTIVE'
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        dni: initialData.dni,
        birthDate: initialData.birthDate || '',
        firstName: initialData.firstName,
        lastName: initialData.lastName,
        email: initialData.email,
        phone: initialData.phone || '',
        address: initialData.address || '',
        level: initialData.level,
        grade: initialData.grade,
        division: initialData.division || '',
        enrollmentDate: initialData.enrollmentDate.split('T')[0],
        status: initialData.status
      });

      if (initialData.tutorName) {
        const names = initialData.tutorName.split(' | ');
        const phones = initialData.tutorPhone?.split(' | ') || [];
        const loadedTutors = names.map((n, i) => ({
          id: i.toString(),
          name: n,
          phone: phones[i] || ''
        }));
        setTutors(loadedTutors);
      }
    }
  }, [initialData]);

  const handleAddTutor = () => {
    setTutors([...tutors, { id: Math.random().toString(36).substr(2, 9), name: '', phone: '' }]);
  };

  const handleRemoveTutor = (id: string) => {
    if (tutors.length > 1) setTutors(tutors.filter(t => t.id !== id));
  };

  const handleTutorChange = (id: string, field: keyof Tutor, value: string) => {
    setTutors(tutors.map(t => t.id === id ? { ...t, [field]: value } : t));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const payload: any = {
        ...formData,
