import React, { useState } from 'react';
import { 
  Users, Home, BookOpen, ClipboardList, CreditCard, ChevronDown, 
  UserPlus, BarChart2, Calendar, GraduationCap, LogOut, Bell, X, Check
} from 'lucide-react';
import { Notification, UserRole } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: UserRole;
  userName?: string;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, userName, onLogout }) => {
  const [expanded, setExpanded] = useState<string | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([
    { id: '1', title: 'Generar Cuotas', message: 'Falta generar el ciclo de Marzo.', type: 'task', date: 'Hace 5 min', read: false },
    { id: '2', title: 'Mesa de Exámenes', message: 'Revisar inscritos en Matemática I.', type: 'info', date: 'Hoy, 09:00', read: false }
  ]);

  const unreadCount = notifications.filter(n => !n.read).length;

  const menu = [
    { id: 'dashboard', label: 'Inicio', icon: Home, roles: ['superadmin', 'school_admin', 'cashier'] },
    { id: 'students', label: 'Alumnos', icon: Users, roles: ['superadmin', 'school_admin'], children: [
      { id: 'students-list', label: 'Lista de Alumnos' },
      { id: 'new-student', label: 'Nuevo Alumno', icon: UserPlus }
    ]},
    { id: 'academic', label: 'Académico', icon: BookOpen, roles: ['superadmin', 'school_admin'], children: [
      { id: 'subjects', label: 'Materias' },
      { id: 'careers', label: 'Carreras' },
      { id: 'enrollments', label: 'Inscripciones' }
    ]},
    { id: 'attendance', label: 'Asistencia', icon: ClipboardList, roles: ['superadmin', 'school_admin', 'teacher'] },
    { id: 'billing', label: 'Cobranzas', icon: CreditCard, roles: ['superadmin', 'cashier'], children: [
      { id: 'fees', label: 'Cuotas' },
      { id: 'billing-config', label: 'Configuración' }
    ]},
    { id: 'reports', label: 'Informes', icon: BarChart2, roles: ['superadmin', 'school_admin'] },
    { id: 'calendar', label: 'Calendario', icon: Calendar, roles: ['superadmin', 'school_admin', 'cashier'] }
  ].filter(item => item.roles.includes(userRole));

  const handleTabClick = (id: string, hasChildren: boolean) => {
    if (hasChildren) {
      setExpanded(expanded === id ? null : id);
    } else {
      setActiveTab(id);
    }
  };

  const markAllAsRead = () => {
    setNotifications(notifications.map(n => ({ ...n, read: true })));
  };

  return (
    <div className="flex min-h-screen bg-[#F8FAFC]">
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col fixed h-full z-20">
        <div className="p-6 flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
            <GraduationCap size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold text-[#1E293B] tracking-tight">EduManager</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Pro System</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-2 space-y-1 overflow-y-auto no-scrollbar">
          {menu.map(item => {
            const Icon = item.icon;
            const isTabActive = activeTab === item.id || (item.children && item.children.some(c => c.id === activeTab));
            const isExpanded = expanded === item.id || isTabActive;

            return (
              <div key={item.id} className="space-y-1">
                <button
                  onClick={() => handleTabClick(item.id, !!item.children)}
                  className={`w-full flex items-center justify-between px-3 py-2.5 rounded-xl transition-all ${
                    isTabActive && !item.children ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <Icon size={18} className={isTabActive ? 'text-indigo-600' : 'text-slate-400'} />
                    <span className="text-sm font-semibold">{item.label}</span>
                  </div>
                  {item.children && (
                    <ChevronDown size={14} className={`transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                  )}
                </button>

                {item.children && isExpanded && (
                  <div className="ml-4 pl-4 border-l border-slate-100 space-y-1 mt-1">
                    {item.children.map(child => (
                      <button
                        key={child.id}
                        onClick={() => setActiveTab(child.id)}
                        className={`w-full text-left px-3 py-2 rounded-lg text-xs font-semibold transition-all ${
                          activeTab === child.id ? 'bg-indigo-50 text-indigo-700' : 'text-slate-400 hover:text-slate-700'
                        }`}
                      >
                        {child.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-50">
          <div className="flex items-center gap-3 p-3 rounded-2xl bg-slate-50/50">
            <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-xs uppercase">
              {userName?.[0] || 'U'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-bold text-slate-800 truncate">{userName}</p>
              <p className="text-[10px] text-indigo-600 font-bold uppercase">{userRole.replace('_', ' ')}</p>
            </div>
            <button onClick={onLogout} className="text-slate-400 hover:text-rose-500 transition-colors">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 ml-64 min-h-screen relative">
        <header className="h-20 border-b border-slate-100 bg-white/80 backdrop-blur-md sticky top-0 z-10 px-8 flex items-center justify-between">
          <h2 className="text-lg font-black text-slate-800 uppercase tracking-tight">
            {activeTab.replace('-', ' ')}
          </h2>
          <div className="flex items-center gap-4">
             <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative p-2.5 text-slate-400 hover:bg-slate-50 rounded-xl transition-all"
             >
                <Bell size={20} />
                {unreadCount > 0 && (
                  <span className="absolute top-2 right-2 w-4 h-4 bg-rose-500 text-white text-[10px] font-bold flex items-center justify-center rounded-full border-2 border-white">
                    {unreadCount}
                  </span>
                )}
             </button>
          </div>
        </header>

        {showNotifications && (
          <div className="absolute right-8 top-20 w-80 bg-white border border-slate-100 rounded-3xl shadow-2xl z-50 overflow-hidden animate-modal">
            <div className="p-4 bg-indigo-600 text-white flex justify-between items-center">
              <h3 className="text-xs font-black uppercase tracking-widest">Notificaciones</h3>
              <button onClick={markAllAsRead} className="text-[10px] font-bold bg-white/20 px-2 py-1 rounded-lg flex items-center gap-1">
                <Check size={12} /> Todo leído
              </button>
            </div>
            <div className="max-h-96 overflow-y-auto p-2">
              {notifications.map(n => (
                <div key={n.id} className={`p-4 rounded-2xl mb-1 ${n.read ? 'opacity-60' : 'bg-indigo-50/50 border border-indigo-100/50'}`}>
                  <div className="flex justify-between items-start mb-1">
                    <p className="text-sm font-bold text-slate-800">{n.title}</p>
                    <span className="text-[10px] text-slate-400 font-medium">{n.date}</span>
                  </div>
                  <p className="text-xs text-slate-500 leading-relaxed">{n.message}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="p-8 max-w-6xl mx-auto">{children}</div>
      </main>
    </div>
  );
};

export default Layout;

