import React, { useState } from 'react';
import { CreditCard, Plus, Search, FileText, CheckCircle2, Clock, AlertCircle, X, Loader2, Save, Printer } from 'lucide-react';
import { Payment } from '../types';
import { INITIAL_PAYMENTS, INITIAL_STUDENTS } from '../constants';

const BillingModule: React.FC<{ view: 'fees' | 'config' }> = ({ view }) => {
  const [payments, setPayments] = useState<Payment[]>(INITIAL_PAYMENTS);
  const [selectedPayment, setSelectedPayment] = useState<Payment | null>(null);
  const [payLoading, setPayLoading] = useState(false);
  const [paymentData, setPaymentData] = useState({
    method: 'Efectivo' as any,
    receipt: ''
  });

  const handleOpenPay = (p: Payment) => {
    setSelectedPayment(p);
    setPaymentData({ method: 'Efectivo', receipt: `REC-${Math.floor(Math.random() * 100000)}` });
  };

  const processPayment = async () => {
    setPayLoading(true);
    await new Promise(r => setTimeout(r, 1000));
    setPayments(prev => prev.map(p => 
      p.id === selectedPayment?.id 
        ? { ...p, isPaid: true, status: 'Pagada', paymentMethod: paymentData.method, receiptNumber: paymentData.receipt, paidAt: new Date().toISOString() } 
        : p
    ));
    setPayLoading(false);
    setSelectedPayment(null);
  };

  if (view === 'fees') {
    return (
      <div className="space-y-6">
        {selectedPayment && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
            <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-md w-full overflow-hidden animate-modal">
              <div className="bg-amber-500 p-6 text-white flex justify-between items-center">
                <h3 className="text-xs font-black uppercase tracking-widest">Procesar Pago</h3>
                <button onClick={() => setSelectedPayment(null)}><X size={20} /></button>
              </div>
              <div className="p-8 space-y-6">
                <div className="text-center bg-slate-50 p-6 rounded-3xl border border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Monto a Cobrar</p>
                  <p className="text-4xl font-black text-slate-800 mt-1">$ {selectedPayment.amount.toLocaleString()}</p>
                </div>

                <div className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Medio de Pago</label>
                    <select 
                      value={paymentData.method}
                      onChange={e => setPaymentData({...paymentData, method: e.target.value})}
                      className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:border-amber-500"
                    >
                      <option>Efectivo</option>
                      <option>Tarjeta de Débito</option>
                      <option>Tarjeta de Crédito</option>
                      <option>Transferencia</option>
                    </select>
                  </div>
                  {(paymentData.method.includes('Tarjeta') || paymentData.method === 'Transferencia') && (
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">N° Comprobante / Operación</label>
                      <input 
                        className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none" 
                        value={paymentData.receipt}
                        onChange={e => setPaymentData({...paymentData, receipt: e.target.value})}
                      />
                    </div>
                  )}
                </div>

                <button 
                  onClick={processPayment}
                  disabled={payLoading}
                  className="w-full py-4 bg-amber-500 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-amber-100 flex items-center justify-center gap-2 hover:scale-[1.02] transition-all"
                >
                  {payLoading ? <Loader2 className="animate-spin" /> : <Save size={18} />} Confirmar Cobro
                </button>
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="text-amber-500 bg-amber-50 p-2.5 rounded-xl">
              <CreditCard size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">Cobranzas</h2>
              <p className="text-sm text-slate-500 font-medium tracking-wide">Caja y gestión de cuotas</p>
            </div>
          </div>
          <button className="bg-amber-500 text-white px-6 py-3 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest shadow-xl shadow-amber-100">
            <Plus size={18} /> Crear Cuota
          </button>
        </div>

        <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex gap-4 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
            <input placeholder="Buscar por alumno o concepto..." className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:border-amber-500" />
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-[#F8FAFC] border-b border-slate-100">
              <tr>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Alumno</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Concepto</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Monto</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Estado</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {payments.map(p => {
                const student = INITIAL_STUDENTS.find(s => s.id === p.studentId);
                return (
                  <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-5">
                      <p className="font-bold text-slate-800">{student?.lastName}, {student?.firstName}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase">{student?.dni}</p>
                    </td>
                    <td className="px-8 py-5 text-center text-slate-600 font-bold text-sm">{p.concept}</td>
                    <td className="px-8 py-5 text-center font-black text-slate-800">$ {p.amount.toLocaleString()}</td>
                    <td className="px-8 py-5 text-center">
                      <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider ${
                        p.isPaid ? 'bg-teal-50 text-teal-600 border border-teal-100' : 'bg-rose-50 text-rose-600 border border-rose-100'
                      }`}>
                        {p.isPaid ? 'Pagada' : 'Pendiente'}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      {p.isPaid ? (
                        <button className="text-indigo-600 flex items-center gap-1 ml-auto text-xs font-black uppercase hover:underline">
                          <Printer size={14} /> Recibo
                        </button>
                      ) : (
                        <button 
                          onClick={() => handleOpenPay(p)}
                          className="bg-slate-800 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-slate-900"
                        >
                          Cobrar
                        </button>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white p-12 rounded-[3rem] border border-slate-100 shadow-sm text-center">
      <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
        <AlertCircle size={40} className="text-slate-300" />
      </div>
      <h3 className="text-xl font-black text-slate-800 mb-2">Configuración de Cobranzas</h3>
      <p className="text-slate-500 max-w-sm mx-auto text-sm font-medium">Aquí puede definir aranceles, ciclos de facturación y descuentos por pago anticipado.</p>
    </div>
  );
};

export default BillingModule;

import React, { useState } from 'react';
import { Search, Filter, Trash2, Edit3, Eye, Users, Loader2, AlertCircle } from 'lucide-react';
import { Student, AcademicLevel } from '../types';
import { usePaginatedQuery } from '../usePaginatedQuery';
import { supabase } from '../supabaseClient';
import StudentDashboard from './StudentDashboard';

interface StudentsModuleProps {
  schoolId: string;
  onEditStudent: (student: Student) => void;
}

const StudentsModule: React.FC<StudentsModuleProps> = ({ schoolId, onEditStudent }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [levelFilter, setLevelFilter] = useState<AcademicLevel | 'ALL'>('ALL');
  const [gradeFilter, setGradeFilter] = useState<string>('ALL');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [selectedStudentForView, setSelectedStudentForView] = useState<Student | null>(null);

  const { data: students, loading, count, page, setPage, refetch } = usePaginatedQuery<Student>(
    'students',
    schoolId,
    25,
    { 
      ...(levelFilter !== 'ALL' ? { level: levelFilter } : {}),
      ...(gradeFilter !== 'ALL' ? { grade: gradeFilter } : {})
    }
  );

  const availableGrades = [
    'Sala 3', 'Sala 4', 'Sala 5',
    '1° Primaria', '2° Primaria', '3° Primaria', '4° Primaria', '5° Primaria', '6° Primaria', '7° Primaria',
    '1° Secundaria', '2° Secundaria', '3° Secundaria', '4° Secundaria', '5° Secundaria', '6° Secundaria',
    '1° Año Terciario', '2° Año Terciario', '3° Año Terciario'
  ];

  const handleDeleteStudent = async (id: string) => {
    setDeletingId(null);
    try {
      await supabase.from('students').delete().eq('id', id);
      refetch();
    } catch (err) {
      console.error(err);
    }
  };

  const getLevelBadgeStyles = (level: AcademicLevel) => {
    switch (level) {
      case AcademicLevel.INITIAL: return 'bg-pink-100 text-pink-600';
      case AcademicLevel.PRIMARY: return 'bg-blue-100 text-blue-600';
      case AcademicLevel.SECONDARY: return 'bg-orange-100 text-orange-600';
      case AcademicLevel.TERTIARY: return 'bg-emerald-100 text-emerald-600';
      default: return 'bg-slate-100 text-slate-600';
    }
  };

  if (selectedStudentForView) {
    return <StudentDashboard student={selectedStudentForView} onBack={() => setSelectedStudentForView(null)} />;
  }

  return (
    <div className="space-y-4 animate-in fade-in duration-500">
      {deletingId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full p-6 animate-modal">
            <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-xl flex items-center justify-center mb-4">
              <AlertCircle size={24} />
            </div>
            <h3 className="text-lg font-bold text-slate-800">¿Eliminar alumno?</h3>
            <p className="text-slate-500 text-sm mt-2 font-medium">Esta acción no se puede deshacer.</p>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setDeletingId(null)} className="flex-1 px-4 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold text-sm hover:bg-slate-50">Cancelar</button>
              <button onClick={() => handleDeleteStudent(deletingId)} className="flex-1 px-4 py-2.5 rounded-xl bg-rose-600 text-white font-bold text-sm hover:bg-rose-700">Eliminar</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-start">
        <div className="flex items-center gap-3">
          <div className="text-indigo-600 bg-indigo-50 p-2 rounded-xl">
            <Users size={24} strokeWidth={2} />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-800 tracking-tight">Alumnos</h2>
            <p className="text-xs text-slate-500 font-medium tracking-wide uppercase">Gestión de Matriculados</p>
          </div>
        </div>
      </div>

      <div className="bg-white p-3 rounded-xl border border-slate-100 shadow-sm flex flex-col md:flex-row gap-3 items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
          <input 
            type="text" 
            placeholder="Buscar alumno..." 
            className="pl-10 pr-4 py-2 w-full bg-slate-50/50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select 
            className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
            value={levelFilter}
            onChange={(e) => setLevelFilter(e.target.value as AcademicLevel | 'ALL')}
          >
            <option value="ALL">Todos los Niveles</option>
            {Object.values(AcademicLevel).map(l => <option key={l} value={l}>{l}</option>)}
          </select>
          <select 
            className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
            value={gradeFilter}
            onChange={(e) => setGradeFilter(e.target.value)}
          >
            <option value="ALL">Todos los Cursos</option>
            {availableGrades.map(g => <option key={g} value={g}>{g}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden relative min-h-[400px]">
        {loading && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] z-10 flex items-center justify-center">
            <Loader2 className="animate-spin text-indigo-600" size={28} />
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">Alumno</th>
                <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">DNI</th>
                <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Curso</th>
                <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Nivel</th>
                <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {students.length > 0 ? students.map((student) => (
                <tr key={student.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-5 py-3.5">
                    <div className="flex items-center gap-3">
                      <div className={`w-8 h-8 rounded-lg bg-indigo-500 flex items-center justify-center text-white text-[10px] font-black shadow-sm`}>
                        {student.firstName[0]}{student.lastName[0]}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-sm">{student.firstName} {student.lastName}</span>
                        <span className="text-[11px] text-slate-400 font-medium">{student.email}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-5 py-3.5 text-slate-500 font-bold text-sm tracking-tight">{student.dni}</td>
                  <td className="px-5 py-3.5 text-center text-slate-600 font-bold text-sm">{student.grade}</td>
                  <td className="px-5 py-3.5 text-center">
                    <span className={`text-[9px] px-2 py-0.5 rounded-lg font-black uppercase ${getLevelBadgeStyles(student.level)}`}>
                      {student.level}
                    </span>
                  </td>
                  <td className="px-5 py-3.5 text-right space-x-1">
                    <button 
                      onClick={() => setSelectedStudentForView(student)}
                      className="p-1.5 text-slate-400 hover:text-indigo-600 transition-all rounded-lg hover:bg-indigo-50" 
                      title="Ver Ficha"
                    >
                      <Eye size={15} />
                    </button>
                    <button onClick={() => onEditStudent(student)} className="p-1.5 text-slate-400 hover:text-indigo-600 transition-all rounded-lg hover:bg-indigo-50" title="Editar">
                      <Edit3 size={15} />
                    </button>
                    <button onClick={() => setDeletingId(student.id)} className="p-1.5 text-rose-300 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50" title="Eliminar">
                      <Trash2 size={15} />
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-slate-400 font-medium text-xs">No hay alumnos registrados.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="px-5 py-3 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
          <p className="text-xs text-slate-500 font-medium">Mostrando {students.length} de {count} alumnos</p>
          <div className="flex gap-2">
            <button disabled={page === 0} onClick={() => setPage(page - 1)} className="px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-xs font-bold disabled:opacity-50 hover:bg-slate-50">Anterior</button>
            <button disabled={(page + 1) * 25 >= count} onClick={() => setPage(page + 1)} className="px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-xs font-bold disabled:opacity-50 hover:bg-slate-50">Siguiente</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentsModule;

export enum AcademicLevel {
  INITIAL = 'Inicial',
  PRIMARY = 'Primaria',
  SECONDARY = 'Secundaria',
