import React, { useState, useEffect } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, GraduationCap, X, Loader2, Save, AlertTriangle } from 'lucide-react';
// Removed non-existent Enrollment type
import { Subject, Career, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view }) => {
  const [dataList, setDataList] = useState<any[]>([]);
  const [careers, setCareers] = useState<Career[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [btnLoading, setBtnLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<any>({});

  const tableMap = {
    subjects: 'subjects',
    careers: 'careers',
    enrollments: 'enrollments'
  };

  useEffect(() => {
    fetchData();
    if (view === 'enrollments') fetchCareers();
  }, [view]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from(tableMap[view]).select('*');
    setDataList(data || []);
    setLoading(false);
  };

  const fetchCareers = async () => {
    const { data } = await supabase.from('careers').select('*');
    setCareers(data || []);
  };

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openNew = () => {
    if (view === 'subjects') setFormData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
    if (view === 'careers') setFormData({ code: '', name: '', duration: '', description: '', status: 'active' });
    if (view === 'enrollments') setFormData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
    setIsModalOpen(true);
  };

  const openEdit = (item: any) => {
    setEditingId(item.id);
    setFormData({ ...item });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    setDeletingId(null);
    try {
      await supabase.from(tableMap[view]).delete().eq('id', id);
      setDataList(prev => prev.filter(i => i.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setBtnLoading(true);
    try {
      if (editingId) {
        await supabase.from(tableMap[view]).update(formData).eq('id', editingId);
      } else {
        const newItem = { ...formData, school_id: 'school-1' };
        await supabase.from(tableMap[view]).insert(newItem);
      }
      await fetchData();
      resetForms();
    } catch (err) {
      console.error(err);
    } finally {
      setBtnLoading(false);
    }
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno Demo';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera';
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-300">
      {deletingId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full p-6 animate-modal">
            <div className="w-10 h-10 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center mb-4">
              <AlertTriangle size={20} />
            </div>
            <h3 className="text-lg font-bold text-slate-800">¿Confirmar borrado?</h3>
            <p className="text-slate-500 text-sm mt-2 font-medium">Esta acción eliminará el registro de {view} permanentemente.</p>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setDeletingId(null)} className="flex-1 px-4 py-2 rounded-lg border border-slate-200 text-slate-600 font-bold text-xs hover:bg-slate-50">Cancelar</button>
              <button onClick={() => handleDelete(deletingId)} className="flex-1 px-4 py-2 rounded-lg bg-rose-600 text-white font-bold text-xs hover:bg-rose-700">Eliminar</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className={`${view === 'careers' ? 'text-emerald-600 bg-emerald-50' : 'text-indigo-600 bg-indigo-50'} p-2 rounded-xl`}>
            {view === 'careers' ? <GraduationCap size={24} /> : <Book size={24} />}
          </div>
          <div>
            <h2 className="text-xl font-black text-[#1E293B] tracking-tight">
              {view === 'subjects' && 'Materias'}
              {view === 'careers' && 'Carreras'}
              {view === 'enrollments' && 'Inscripciones'}
            </h2>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Panel de Control Académico</p>
          </div>
        </div>
        <button 
          onClick={openNew}
          className={`${view === 'careers' ? 'bg-[#10B981]' : 'bg-indigo-600'} text-white px-4 py-2 rounded-lg flex items-center gap-2 font-bold text-xs uppercase tracking-widest shadow-lg btn-transition`}
        >
          <Plus size={16} /> Añadir
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-modal">
            <div className={`p-4 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white flex justify-between items-center`}>
              <h3 className="text-xs font-black uppercase tracking-widest">{editingId ? 'Editar' : 'Nuevo'} Registro</h3>
              <button onClick={resetForms}><X size={18} /></button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-4">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Código</label>
                      <input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold focus:border-indigo-500 transition-all" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Hs/Sem</label>
                      <input required type="number" className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold focus:border-indigo-500 transition-all" value={formData.hoursPerWeek || 0} onChange={e => setFormData({...formData, hoursPerWeek: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nombre</label>
                    <input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold focus:border-indigo-500 transition-all" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'careers' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Código</label>
                      <input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-emerald-600 text-sm font-bold" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Duración</label>
                      <input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-emerald-600 text-sm font-bold" value={formData.duration || ''} onChange={e => setFormData({...formData, duration: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nombre Carrera</label>
                    <input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-emerald-600 text-sm font-bold" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'enrollments' && (
                <div className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Alumno</label>
                    <select required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold" value={formData.studentId || ''} onChange={e => setFormData({...formData, studentId: e.target.value})}>
                      <option value="">Seleccionar alumno...</option>
                      {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.lastName}, {s.firstName}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Carrera</label>
                    <select required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold" value={formData.careerId || ''} onChange={e => setFormData({...formData, careerId: e.target.value})}>
                      <option value="">Seleccionar carrera...</option>
                      {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                </div>
              )}

              <button disabled={btnLoading} className={`w-full p-3.5 ${view === 'careers' ? 'bg-emerald-600' : 'bg-indigo-600'} text-white rounded-lg font-black uppercase tracking-widest text-[10px] shadow-lg flex items-center justify-center gap-2 mt-2`}>
                {btnLoading ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />} Guardar Datos
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden min-h-[300px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/60 z-10 flex items-center justify-center">
            <Loader2 className="animate-spin text-indigo-600" size={24} />
          </div>
        )}
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descripción</th>
              <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Referencia</th>
              <th className="px-5 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm font-medium">
            {dataList.map(item => (
              <tr key={item.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-5 py-3.5">
                  <div className="font-bold text-slate-800">
                    {view === 'enrollments' ? getStudentName(item.studentId) : item.name}
                  </div>
                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">
                    {view === 'enrollments' ? `REF: ${item.id.slice(0, 8)}` : item.code}
                  </div>
                </td>
                <td className="px-5 py-3.5 text-center text-slate-500 font-bold">
                  {view === 'subjects' && item.grade}
                  {view === 'careers' && <span className="flex items-center justify-center gap-1"><Clock size={12} /> {item.duration}</span>}
                  {view === 'enrollments' && getCareerName(item.careerId)}
                </td>
                <td className="px-5 py-3.5 text-right space-x-1">
                  <button onClick={() => openEdit(item)} className="p-1.5 text-slate-400 hover:text-indigo-600 transition-all rounded-lg hover:bg-indigo-50"><Edit3 size={15} /></button>
                  <button onClick={() => setDeletingId(item.id)} className="p-1.5 text-rose-300 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50"><Trash2 size={15} /></button>
                </td>
              </tr>
            ))}
            {dataList.length === 0 && !loading && (
              <tr><td colSpan={3} className="py-20 text-center text-slate-400 italic text-xs">No hay registros</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

