import React, { useState, useEffect } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, GraduationCap, X, Loader2, Save, AlertTriangle, ChevronDown } from 'lucide-react';
import { Subject, Career, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view }) => {
  const [dataList, setDataList] = useState<any[]>([]);
  const [careers, setCareers] = useState<Career[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [btnLoading, setBtnLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<any>({});

  const tableMap = {
    subjects: 'subjects',
    careers: 'careers',
    enrollments: 'enrollments'
  };

  useEffect(() => {
    fetchData();
    if (view === 'enrollments') fetchCareers();
  }, [view]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from(tableMap[view]).select('*');
    setDataList(data || []);
    setLoading(false);
  };

  const fetchCareers = async () => {
    const { data } = await supabase.from('careers').select('*');
    setCareers(data || []);
  };

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openNew = () => {
    if (view === 'subjects') setFormData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
    if (view === 'careers') setFormData({ code: '', name: '', duration: '', description: '', status: 'active' });
    if (view === 'enrollments') setFormData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
    setIsModalOpen(true);
  };

  const openEdit = (item: any) => {
    setEditingId(item.id);
    setFormData({ ...item });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    setDeletingId(null);
    try {
      await supabase.from(tableMap[view]).delete().eq('id', id);
      setDataList(prev => prev.filter(i => i.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setBtnLoading(true);
    try {
      if (editingId) {
        await supabase.from(tableMap[view]).update(formData).eq('id', editingId);
      } else {
        const newItem = { ...formData, school_id: 'school-1' };
        await supabase.from(tableMap[view]).insert(newItem);
      }
      await fetchData();
      resetForms();
    } catch (err) {
      console.error(err);
    } finally {
      setBtnLoading(false);
    }
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno Demo';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera';
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Modal de Confirmación de Borrado */}
      {deletingId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-sm w-full p-8 animate-modal space-y-4 text-center">
            <div className="w-16 h-16 bg-rose-50 text-rose-600 rounded-full flex items-center justify-center mx-auto border border-rose-100">
              <AlertTriangle size={32} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-900">¿Confirmar borrado?</h3>
              <p className="text-slate-500 text-sm mt-1">Esta acción eliminará el registro de {view} permanentemente.</p>
            </div>
            <div className="flex gap-3 pt-2">
              <button onClick={() => setDeletingId(null)} className="flex-1 px-4 py-3 rounded-xl border border-slate-200 text-slate-700 font-bold text-sm hover:bg-slate-50">Cancelar</button>
              <button onClick={() => handleDelete(deletingId)} className="flex-1 px-4 py-3 rounded-xl bg-rose-600 text-white font-bold text-sm hover:bg-rose-700 shadow-lg shadow-rose-100">Eliminar</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="text-slate-900 bg-white border border-slate-200 p-3 rounded-xl shadow-sm">
            {view === 'careers' ? <GraduationCap size={24} /> : <Book size={24} />}
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-900 tracking-tight capitalize">{view.replace('s', '') === 'enrollment' ? 'Inscripciones' : view === 'careers' ? 'Carreras' : 'Materias'}</h2>
            <p className="text-sm text-slate-500 font-medium">Gestión del currículo y matriculaciones</p>
          </div>
        </div>
        <button 
          onClick={openNew}
          className="bg-[#1e293b] text-white px-6 py-3 rounded-xl flex items-center gap-2 font-bold text-sm shadow-lg hover:bg-slate-800 transition-all"
        >
          <Plus size={18} /> Añadir
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-8 animate-modal space-y-6 relative">
            <button onClick={resetForms} className="absolute top-6 right-6 text-slate-400 hover:text-slate-600"><X size={20} /></button>
            <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Editar' : 'Nuevo'} Registro</h3>

            <form onSubmit={handleSave} className="space-y-4">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Código <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Hs/Sem <span className="text-rose-500">*</span></label>
                      <input required type="number" className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.hoursPerWeek || 0} onChange={e => setFormData({...formData, hoursPerWeek: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Nombre <span className="text-rose-500">*</span></label>
                    <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'careers' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Código <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Duración <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.duration || ''} onChange={e => setFormData({...formData, duration: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Nombre Carrera <span className="text-rose-500">*</span></label>
                    <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}

              {view === 'enrollments' && (
                <div className="space-y-4">
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Alumno <span className="text-rose-500">*</span></label>
                    <div className="relative">
                      <select required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none appearance-none text-sm focus:border-slate-900 pr-10" value={formData.studentId || ''} onChange={e => setFormData({...formData, studentId: e.target.value})}>
                        <option value="">Seleccionar</option>
                        {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.lastName}, {s.firstName}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Carrera <span className="text-rose-500">*</span></label>
                    <div className="relative">
                      <select required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none appearance-none text-sm focus:border-slate-900 pr-10" value={formData.careerId || ''} onChange={e => setFormData({...formData, careerId: e.target.value})}>
                        <option value="">Seleccionar</option>
                        {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>
                  </div>
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={resetForms} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-50 transition-all">Cancelar</button>
                <button disabled={btnLoading} className="flex-1 py-3 bg-[#1e293b] text-white rounded-xl font-bold text-sm shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                  {btnLoading ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />} Guardar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden min-h-[400px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/60 z-10 flex items-center justify-center">
            <Loader2 className="animate-spin text-slate-900" size={28} />
          </div>
        )}
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Descripción</th>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Referencia</th>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm font-medium">
            {dataList.map(item => (
              <tr key={item.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-4">
                  <div className="font-bold text-slate-900">
                    {view === 'enrollments' ? getStudentName(item.studentId) : item.name}
                  </div>
                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">
                    {view === 'enrollments' ? `REF: ${item.id.slice(0, 8)}` : item.code}
                  </div>
                </td>
                <td className="px-8 py-4 text-center text-slate-500 font-bold">
                  {view === 'subjects' && item.grade}
                  {view === 'careers' && <span className="flex items-center justify-center gap-1.5"><Clock size={12} /> {item.duration}</span>}
                  {view === 'enrollments' && getCareerName(item.careerId)}
                </td>
                <td className="px-8 py-4 text-right space-x-2">
                  <button onClick={() => openEdit(item)} className="p-2 text-slate-400 hover:text-slate-900 transition-all rounded-lg hover:bg-slate-50"><Edit3 size={15} /></button>
                  <button onClick={() => setDeletingId(item.id)} className="p-2 text-rose-300 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50"><Trash2 size={15} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

