import React, { useState } from 'react';
import { 
  Users, Home, BookOpen, ClipboardList, CreditCard, ChevronDown, 
  UserPlus, BarChart2, Calendar, GraduationCap, LogOut, Bell, X, Check
} from 'lucide-react';
import { Notification, UserRole } from '../types';

interface LayoutProps {
  // Fixed: PreactNode does not exist in React namespace, should be ReactNode
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: UserRole;
  userName?: string;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, userName, onLogout }) => {
  const [expanded, setExpanded] = useState<string | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([
    { id: '1', title: 'Generar Cuotas', message: 'Falta generar el ciclo de Marzo.', type: 'task', date: 'Hace 5 min', read: false },
    { id: '2', title: 'Mesa de Exámenes', message: 'Revisar inscritos en Matemática I.', type: 'info', date: 'Hoy, 09:00', read: false }
  ]);

  const unreadCount = notifications.filter(n => !n.read).length;

  const menu = [
    { id: 'dashboard', label: 'Inicio', icon: Home, roles: ['superadmin', 'school_admin', 'cashier'] },
    { id: 'students', label: 'Alumnos', icon: Users, roles: ['superadmin', 'school_admin'], children: [
      { id: 'students-list', label: 'Lista de Alumnos' },
      { id: 'new-student', label: 'Nuevo Alumno', icon: UserPlus }
    ]},
    { id: 'academic', label: 'Académico', icon: BookOpen, roles: ['superadmin', 'school_admin'], children: [
      { id: 'subjects', label: 'Materias' },
      { id: 'careers', label: 'Carreras' },
      { id: 'enrollments', label: 'Inscripciones' }
    ]},
    { id: 'attendance', label: 'Asistencia', icon: ClipboardList, roles: ['superadmin', 'school_admin', 'teacher'] },
    { id: 'billing', label: 'Cobranzas', icon: CreditCard, roles: ['superadmin', 'cashier'], children: [
      { id: 'fees', label: 'Cuotas' },
      { id: 'billing-config', label: 'Configuración' }
    ]},
    { id: 'reports', label: 'Informes', icon: BarChart2, roles: ['superadmin', 'school_admin'] },
    { id: 'calendar', label: 'Calendario', icon: Calendar, roles: ['superadmin', 'school_admin', 'cashier'] }
  ].filter(item => item.roles.includes(userRole));

  const handleTabClick = (id: string, hasChildren: boolean) => {
    if (hasChildren) {
      setExpanded(expanded === id ? null : id);
    } else {
      setActiveTab(id);
    }
  };

  const markAllAsRead = () => {
    setNotifications(notifications.map(n => ({ ...n, read: true })));
  };

  return (
    <div className="flex min-h-screen bg-[#F8FAFC]">
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col fixed h-full z-20">
        <div className="p-8 flex items-center gap-3">
          <div className="w-11 h-11 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-lg shadow-slate-200">
            <GraduationCap size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight">EduManager</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Pro System</p>
          </div>
        </div>

        <nav className="flex-1 px-5 py-2 space-y-1 overflow-y-auto no-scrollbar">
          {menu.map(item => {
            const Icon = item.icon;
            const isTabActive = activeTab === item.id || (item.children && item.children.some(c => c.id === activeTab));
            const isExpanded = expanded === item.id || isTabActive;

            return (
              <div key={item.id} className="space-y-1">
                <button
                  onClick={() => handleTabClick(item.id, !!item.children)}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${
                    isTabActive && !item.children ? 'bg-slate-900 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <Icon size={18} className={isTabActive && !item.children ? 'text-white' : 'text-slate-400'} />
                    <span className="text-sm font-semibold">{item.label}</span>
                  </div>
                  {item.children && (
                    <ChevronDown size={14} className={`transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                  )}
                </button>

                {item.children && isExpanded && (
                  <div className="ml-5 pl-4 border-l border-slate-100 space-y-1 mt-1">
                    {item.children.map(child => (
                      <button
                        key={child.id}
                        onClick={() => setActiveTab(child.id)}
                        className={`w-full text-left px-4 py-2.5 rounded-xl text-xs font-semibold transition-all ${
                          // Fixed: removed extra colon and combined hover classes
                          activeTab === child.id ? 'bg-slate-100 text-slate-900' : 'text-slate-400 hover:text-slate-700 hover:bg-slate-50'
                        }`}
                      >
                        {child.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        <div className="p-6 border-t border-slate-50">
          <div className="flex items-center gap-3 p-3.5 rounded-2xl bg-slate-50 border border-slate-100">
            <div className="w-10 h-10 bg-slate-900 rounded-full flex items-center justify-center text-white font-bold text-xs">
              {userName?.[0] || 'U'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-bold text-slate-800 truncate">{userName}</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase">{userRole.replace('_', ' ')}</p>
            </div>
            <button onClick={onLogout} className="text-slate-400 hover:text-rose-600 transition-colors">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 ml-64 min-h-screen relative">
        <header className="h-20 border-b border-slate-100 bg-white/80 backdrop-blur-md sticky top-0 z-10 px-10 flex items-center justify-between">
          <h2 className="text-lg font-bold text-slate-900 capitalize tracking-tight">
            {activeTab.replace('-', ' ')}
          </h2>
          <div className="flex items-center gap-4">
             <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative p-2.5 text-slate-400 hover:bg-slate-50 rounded-xl transition-all border border-slate-100 bg-white"
             >
                <Bell size={20} />
                {unreadCount > 0 && (
                  <span className="absolute top-2 right-2 w-4 h-4 bg-slate-900 text-white text-[9px] font-bold flex items-center justify-center rounded-full border-2 border-white">
                    {unreadCount}
                  </span>
                )}
             </button>
          </div>
        </header>

        {showNotifications && (
          <div className="absolute right-10 top-20 w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-modal">
            <div className="p-5 bg-slate-900 text-white flex justify-between items-center">
              <h3 className="text-xs font-bold uppercase tracking-widest">Notificaciones</h3>
              <button onClick={markAllAsRead} className="text-[10px] font-bold bg-white/10 px-2 py-1 rounded-lg">
                Leído
              </button>
            </div>
            <div className="max-h-96 overflow-y-auto p-2 bg-white">
              {notifications.map(n => (
                <div key={n.id} className={`p-4 rounded-xl mb-1 ${n.read ? 'opacity-40' : 'bg-slate-50 border border-slate-100'}`}>
                  <p className="text-sm font-bold text-slate-900">{n.title}</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">{n.message}</p>
                  <span className="text-[10px] text-slate-400 font-medium block mt-2">{n.date}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="p-10 max-w-6xl mx-auto">{children}</div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { 
  CreditCard, Plus, Search, FileText, CheckCircle2, 
  Clock, AlertCircle, X, Loader2, Save, Printer, 
  Download, Send, Settings, Calendar, DollarSign, ChevronRight,
  MessageCircle, Mail, UserPlus, ChevronDown
} from 'lucide-react';
import { Payment, AcademicLevel, Student } from '../types';
import { INITIAL_PAYMENTS, INITIAL_STUDENTS, LEVEL_FEES as INITIAL_LEVEL_FEES } from '../constants';

const BillingModule: React.FC<{ view: 'fees' | 'config' }> = ({ view }) => {
  const [payments, setPayments] = useState<Payment[]>(INITIAL_PAYMENTS);
  const [students] = useState<Student[]>(INITIAL_STUDENTS);
  const [levelFees, setLevelFees] = useState(INITIAL_LEVEL_FEES);

  // UI States
  const [selectedPayment, setSelectedPayment] = useState<Payment | null>(null);
  const [showReceipt, setShowReceipt] = useState<Payment | null>(null);
  const [showManualFeeModal, setShowManualFeeModal] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showMassGenModal, setShowMassGenModal] = useState(false);
  const [showSendOptions, setShowSendOptions] = useState<Payment | null>(null);

  // Filtering states
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('Todos');

  // Loading states
  const [actionLoading, setActionLoading] = useState(false);

  // Form states
  const [paymentData, setPaymentData] = useState({
    method: 'Efectivo' as any,
    receipt: ''
  });

  const [manualFee, setManualFee] = useState({
    studentId: '',
    concept: 'Cuota Mensual',
    amount: 0,
    dueDate: new Date().toISOString().split('T')[0]
  });

  const [configData, setConfigData] = useState({
    level: '' as any,
    year: '2026',
    monthlyFee: 50000,
    annualEnrollment: 100000,
    dueDay: 10
  });

  // Filter logic
  const filteredPayments = useMemo(() => {
    return payments.filter(p => {
      const student = students.find(s => s.id === p.studentId);
      const studentName = `${student?.firstName} ${student?.lastName}`.toLowerCase();
      const matchesSearch = studentName.includes(searchTerm.toLowerCase()) || 
                           student?.dni.includes(searchTerm) || 
                           p.concept.toLowerCase().includes(searchTerm.toLowerCase());

      const isVencida = !p.isPaid && new Date(p.dueDate) < new Date();
      let matchesStatus = true;
      if (statusFilter === 'Pagadas') matchesStatus = p.isPaid;
      if (statusFilter === 'Pendientes') matchesStatus = !p.isPaid && !isVencida;
      if (statusFilter === 'Vencidas') matchesStatus = isVencida;

      return matchesSearch && matchesStatus;
    });
  }, [payments, searchTerm, statusFilter, students]);

  const handleOpenPay = (p: Payment) => {
    setSelectedPayment(p);
    setPaymentData({ method: 'Efectivo', receipt: `REC-${Math.floor(Math.random() * 100000)}` });
  };

  const processPayment = async () => {
    setActionLoading(true);
    await new Promise(r => setTimeout(r, 1000));
    const updatedPayment: Payment = { 
      ...selectedPayment!, 
      isPaid: true, 
      status: 'Pagada' as const, 
      paymentMethod: paymentData.method, 
      receiptNumber: paymentData.receipt, 
      paidAt: new Date().toISOString() 
    };

    setPayments(prev => prev.map(p => p.id === selectedPayment?.id ? updatedPayment : p));
    setActionLoading(false);
    setSelectedPayment(null);
    setShowReceipt(updatedPayment);
  };

  const createManualFee = async () => {
    if (!manualFee.studentId || manualFee.amount <= 0) return;
    setActionLoading(true);
    await new Promise(r => setTimeout(r, 800));
    const newFee: Payment = {
      id: `p-man-${Date.now()}`,
      studentId: manualFee.studentId,
      concept: manualFee.concept,
      amount: manualFee.amount,
      dueDate: manualFee.dueDate,
      status: 'Pendiente',
      isPaid: false
    };
    setPayments([newFee, ...payments]);
    setActionLoading(false);
    setShowManualFeeModal(false);
  };

  const runMassGeneration = async () => {
    setActionLoading(true);
    await new Promise(r => setTimeout(r, 2000));
    const newFees: Payment[] = students
      .filter(s => s.status === 'ACTIVE')
      .map(s => ({
        id: `p-auto-${s.id}-${Date.now()}`,
        studentId: s.id,
        concept: 'Cuota Marzo 2026',
        amount: levelFees[s.level] || 0,
        dueDate: '2026-03-10',
        status: 'Pendiente',
        isPaid: false
      }));
    setPayments([...newFees, ...payments]);
    setActionLoading(false);
    setShowMassGenModal(false);
  };

  const handleEditArancel = (level: AcademicLevel) => {
    setConfigData({
      level,
      year: '2026',
      monthlyFee: levelFees[level],
      annualEnrollment: 100000,
      dueDay: 10
    });
    setShowConfigModal(true);
  };

  const saveConfig = () => {
    if (!configData.level) return;
    setLevelFees({
      ...levelFees,
      [configData.level]: configData.monthlyFee
    });
    setShowConfigModal(false);
  };

  const handleDownload = (p: Payment) => {
    alert(`Iniciando descarga de comprobante ${p.receiptNumber}...`);
  };

  const handleSendAction = (type: 'whatsapp' | 'email') => {
    const method = type === 'whatsapp' ? 'WhatsApp' : 'Email';
    alert(`Comprobante enviado vía ${method} al tutor responsable.`);
    setShowSendOptions(null);
  };

  const ReceiptView = ({ payment, onClose }: { payment: Payment, onClose: () => void }) => {
    const student = students.find(s => s.id === payment.studentId);
    return (
      <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
        <div className="bg-white rounded-2xl shadow-xl max-w-lg w-full overflow-hidden animate-modal">
          <div className="bg-slate-900 p-8 text-white flex justify-between items-center relative overflow-hidden">
            <div className="relative z-10">
              <h3 className="text-xl font-bold tracking-tight">Comprobante de Pago</h3>
              <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">EduManager Pro System</p>
            </div>
            <FileText size={60} className="absolute -right-4 -bottom-4 text-white/5 rotate-12" />
            <button onClick={onClose} className="relative z-10 p-2 hover:bg-white/10 rounded-full transition-colors">
              <X size={20} />
            </button>
          </div>
          <div className="p-8 space-y-6 bg-white">
            <div className="flex justify-between items-start border-b border-slate-100 pb-6">
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Alumno</p>
                <p className="text-base font-bold text-slate-800">{student?.lastName}, {student?.firstName}</p>
                <p className="text-xs text-slate-500">{student?.dni}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">N° Comprobante</p>
                <p className="text-sm font-bold text-slate-900">{payment.receiptNumber}</p>
              </div>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between text-sm">
                <span className="text-slate-500">{payment.concept}</span>
                <span className="text-slate-900 font-bold">$ {payment.amount.toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-xs border-t border-slate-50 pt-3">
                <span className="text-slate-400">Medio de Pago</span>
                <span className="text-slate-600 font-bold">{payment.paymentMethod}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-400">Fecha de Pago</span>
                <span className="text-slate-600 font-bold">{new Date(payment.paidAt || '').toLocaleDateString('es-AR')}</span>
              </div>
            </div>
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 flex items-center justify-between">
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Abonado</p>
                <p className="text-3xl font-black text-slate-900">$ {payment.amount.toLocaleString()}</p>
              </div>
              <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-emerald-500 shadow-sm border border-slate-100">
                <CheckCircle2 size={24} />
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <button onClick={() => handleDownload(payment)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-slate-50 transition-all">
                <Download size={16} /> Descargar
              </button>
              <button onClick={() => setShowSendOptions(payment)} className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 shadow-lg hover:bg-slate-800 transition-all">
                <Send size={16} /> Enviar
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {showReceipt && <ReceiptView payment={showReceipt} onClose={() => setShowReceipt(null)} />}
      {showSendOptions && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-sm w-full p-8 animate-modal">
            <h3 className="text-lg font-bold text-slate-900 mb-2">Enviar Comprobante</h3>
            <p className="text-sm text-slate-500 mb-6">Seleccione el medio de envío para el tutor.</p>
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => handleSendAction('whatsapp')} className="flex flex-col items-center gap-3 p-6 bg-emerald-50 border border-emerald-100 rounded-2xl group hover:bg-emerald-600 transition-all">
                <MessageCircle size={32} className="text-emerald-600 group-hover:text-white" />
                <span className="text-[10px] font-bold uppercase text-emerald-700 group-hover:text-white">WhatsApp</span>
