            <button onClick={() => setShowSendOptions(null)} className="w-full mt-6 py-2 text-[10px] font-bold uppercase text-slate-400 hover:text-slate-600">Cancelar</button>
          </div>
        </div>
      )}
      {showConfigModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-md w-full p-8 animate-modal space-y-6 relative">
            <button onClick={() => setShowConfigModal(false)} className="absolute top-6 right-6 text-slate-400 hover:text-slate-600">
              <X size={20} />
            </button>
            <h3 className="text-xl font-semibold text-slate-900">Configuración de Arancel</h3>
            <div className="grid grid-cols-2 gap-4">
