import React, { useState, useEffect } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, GraduationCap, X, Loader2, Save, AlertTriangle, ChevronDown } from 'lucide-react';
import { Subject, Career, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view }) => {
  const [dataList, setDataList] = useState<any[]>([]);
  const [careers, setCareers] = useState<Career[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [btnLoading, setBtnLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<any>({});

  const tableMap = {
    subjects: 'subjects',
    careers: 'careers',
    enrollments: 'enrollments'
  };

  useEffect(() => {
    fetchData();
    if (view === 'enrollments') fetchCareers();
  }, [view]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from(tableMap[view]).select('*');
    setDataList(data || []);
    setLoading(false);
  };

  const fetchCareers = async () => {
    const { data } = await supabase.from('careers').select('*');
    setCareers(data || []);
  };

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openNew = () => {
    if (view === 'subjects') setFormData({ code: '', name: '', level: AcademicLevel.TERTIARY, grade: '', hoursPerWeek: 4 });
    if (view === 'careers') setFormData({ code: '', name: '', duration: '', description: '', status: 'active' });
    if (view === 'enrollments') setFormData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
    setIsModalOpen(true);
  };

  const openEdit = (item: any) => {
    setEditingId(item.id);
    setFormData({ ...item });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    setDeletingId(null);
    try {
      await supabase.from(tableMap[view]).delete().eq('id', id);
      setDataList(prev => prev.filter(i => i.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setBtnLoading(true);
    try {
      if (editingId) {
        await supabase.from(tableMap[view]).update(formData).eq('id', editingId);
      } else {
        const newItem = { ...formData, school_id: 'school-1' };
        await supabase.from(tableMap[view]).insert(newItem);
      }
      await fetchData();
      resetForms();
    } catch (err) {
      console.error(err);
    } finally {
      setBtnLoading(false);
    }
  };

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno Demo';
  };

  const getCareerName = (id: string) => {
    const c = careers.find(car => car.id === id);
    return c ? c.name : 'Carrera';
  };

  const getTitle = () => {
    if (view === 'subjects') return 'Gestión de Materias';
    if (view === 'careers') return 'Gestión de Carreras';
    return 'Control de Inscripciones';
  };

  const getSubTitle = () => {
    if (view === 'subjects') return 'Diseño curricular por nivel y curso';
    if (view === 'careers') return 'Oferta educativa institucional';
    return 'Matriculación de alumnos a carreras';
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      {deletingId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-sm w-full p-8 animate-modal space-y-4 text-center">
            <div className="w-16 h-16 bg-rose-50 text-rose-600 rounded-full flex items-center justify-center mx-auto border border-rose-100">
              <AlertTriangle size={32} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-900">¿Confirmar borrado?</h3>
              <p className="text-slate-500 text-sm mt-1">Esta acción eliminará el registro de {view} permanentemente.</p>
            </div>
            <div className="flex gap-3 pt-2">
              <button onClick={() => setDeletingId(null)} className="flex-1 px-4 py-3 rounded-xl border border-slate-200 text-slate-700 font-bold text-sm hover:bg-slate-50">Cancelar</button>
              <button onClick={() => handleDelete(deletingId)} className="flex-1 px-4 py-3 rounded-xl bg-rose-600 text-white font-bold text-sm hover:bg-rose-700 shadow-lg shadow-rose-100">Eliminar</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="text-slate-900 bg-white border border-slate-200 p-3 rounded-xl shadow-sm">
            {view === 'careers' ? <GraduationCap size={24} /> : <Book size={24} />}
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-900 tracking-tight">{getTitle()}</h2>
            <p className="text-sm text-slate-500 font-medium">{getSubTitle()}</p>
          </div>
        </div>
        <button 
          onClick={openNew}
          className="bg-slate-900 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-bold text-sm shadow-lg hover:bg-slate-800 transition-all"
        >
          <Plus size={18} /> Nuevo Registro
        </button>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-8 animate-modal space-y-6 relative">
            <button onClick={resetForms} className="absolute top-6 right-6 text-slate-400 hover:text-slate-600"><X size={20} /></button>
            <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Editar' : 'Nuevo'} Registro</h3>
            <form onSubmit={handleSave} className="space-y-4">
              {view === 'subjects' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Código <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Hs/Sem <span className="text-rose-500">*</span></label>
                      <input required type="number" className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.hoursPerWeek || 0} onChange={e => setFormData({...formData, hoursPerWeek: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Nombre de Materia <span className="text-rose-500">*</span></label>
                    <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none text-sm focus:border-slate-900" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}
              {view === 'careers' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Código <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.code || ''} onChange={e => setFormData({...formData, code: e.target.value})} />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-sm font-medium text-slate-700">Duración <span className="text-rose-500">*</span></label>
                      <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.duration || ''} onChange={e => setFormData({...formData, duration: e.target.value})} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Nombre de Carrera <span className="text-rose-500">*</span></label>
                    <input required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-slate-900 text-sm" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </>
              )}
              {view === 'enrollments' && (
                <div className="space-y-4">
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Alumno <span className="text-rose-500">*</span></label>
                    <div className="relative">
                      <select required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none appearance-none text-sm focus:border-slate-900 pr-10" value={formData.studentId || ''} onChange={e => setFormData({...formData, studentId: e.target.value})}>
                        <option value="">Seleccionar Alumno</option>
                        {INITIAL_STUDENTS.map(s => <option key={s.id} value={s.id}>{s.lastName}, {s.firstName}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-sm font-medium text-slate-700">Carrera <span className="text-rose-500">*</span></label>
                    <div className="relative">
                      <select required className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none appearance-none text-sm focus:border-slate-900 pr-10" value={formData.careerId || ''} onChange={e => setFormData({...formData, careerId: e.target.value})}>
                        <option value="">Seleccionar Carrera</option>
                        {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>
                  </div>
                </div>
              )}
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={resetForms} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-50 transition-all">Cancelar</button>
                <button disabled={btnLoading} className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                  {btnLoading ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />} Guardar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden min-h-[400px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/60 z-10 flex items-center justify-center">
            <Loader2 className="animate-spin text-slate-900" size={28} />
          </div>
        )}
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Descripción / Nombre</th>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Referencia Académica</th>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm font-medium">
            {dataList.map(item => (
              <tr key={item.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-4">
                  <div className="font-bold text-slate-900">
                    {view === 'enrollments' ? getStudentName(item.studentId) : item.name}
                  </div>
                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">
                    {view === 'enrollments' ? `ID: ${item.id.slice(0, 8)}` : item.code}
                  </div>
                </td>
                <td className="px-8 py-4 text-center text-slate-500 font-bold">
                  {view === 'subjects' && <span className="px-3 py-1 bg-slate-100 rounded-lg text-[10px]">{item.grade}</span>}
                  {view === 'careers' && <span className="flex items-center justify-center gap-1.5 text-xs"><Clock size={12} /> {item.duration}</span>}
                  {view === 'enrollments' && <span className="text-slate-800">{getCareerName(item.careerId)}</span>}
                </td>
                <td className="px-8 py-4 text-right space-x-2">
                  <button onClick={() => openEdit(item)} className="p-2 text-slate-400 hover:text-slate-900 transition-all rounded-lg hover:bg-slate-50"><Edit3 size={15} /></button>
                  <button onClick={() => setDeletingId(item.id)} className="p-2 text-rose-300 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50"><Trash2 size={15} /></button>
                </td>
              </tr>
            ))}
            {dataList.length === 0 && !loading && (
              <tr>
                <td colSpan={3} className="py-20 text-center text-slate-400 font-medium italic">No se encontraron registros.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AcademicModule;

import React, { useState } from 'react';
import { 
  Users, Home, BookOpen, ClipboardList, CreditCard, ChevronDown, 
  UserPlus, BarChart2, Calendar, GraduationCap, LogOut, Bell, X, Check
} from 'lucide-react';
import { Notification, UserRole } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: UserRole;
  userName?: string;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, userName, onLogout }) => {
  const [expanded, setExpanded] = useState<string | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([
    { id: '1', title: 'Generar Cuotas', message: 'Falta generar el ciclo de Marzo.', type: 'task', date: 'Hace 5 min', read: false },
    { id: '2', title: 'Mesa de Exámenes', message: 'Revisar inscritos en Matemática I.', type: 'info', date: 'Hoy, 09:00', read: false }
  ]);

  const unreadCount = notifications.filter(n => !n.read).length;

  const menu = [
    { id: 'dashboard', label: 'Inicio', icon: Home, roles: ['superadmin', 'school_admin', 'cashier'] },
    { id: 'students', label: 'Alumnos', icon: Users, roles: ['superadmin', 'school_admin'], children: [
      { id: 'students-list', label: 'Lista de Alumnos' },
      { id: 'new-student', label: 'Nuevo Alumno', icon: UserPlus }
    ]},
    { id: 'academic', label: 'Académico', icon: BookOpen, roles: ['superadmin', 'school_admin'], children: [
      { id: 'subjects', label: 'Materias' },
      { id: 'careers', label: 'Carreras' },
      { id: 'enrollments', label: 'Inscripciones' }
    ]},
    { id: 'attendance', label: 'Asistencia', icon: ClipboardList, roles: ['superadmin', 'school_admin', 'teacher'] },
    { id: 'billing', label: 'Cobranzas', icon: CreditCard, roles: ['superadmin', 'cashier'], children: [
      { id: 'fees', label: 'Gestión de Cuotas' },
      { id: 'billing-config', label: 'Aranceles' }
    ]},
    { id: 'reports', label: 'Informes', icon: BarChart2, roles: ['superadmin', 'school_admin'] },
    { id: 'calendar', label: 'Calendario', icon: Calendar, roles: ['superadmin', 'school_admin', 'cashier'] }
  ].filter(item => item.roles.includes(userRole));

  const handleTabClick = (id: string, hasChildren: boolean) => {
    if (hasChildren) {
      setExpanded(expanded === id ? null : id);
    } else {
      setActiveTab(id);
    }
  };

  const getHeaderTitle = (id: string) => {
    switch (id) {
      case 'dashboard': return 'Panel de Inicio';
      case 'students-list': return 'Lista de Alumnos';
      case 'new-student': return 'Registro de Alumno';
      case 'subjects': return 'Materias';
      case 'careers': return 'Carreras';
      case 'enrollments': return 'Inscripciones';
      case 'attendance': return 'Control de Asistencia';
      case 'fees': return 'Gestión de Cuotas';
      case 'billing-config': return 'Configuración de Aranceles';
      case 'reports': return 'Informes Institucionales';
      case 'calendar': return 'Calendario Académico';
      default: return id.replace('-', ' ').toUpperCase();
    }
  };

  const markAllAsRead = () => {
    setNotifications(notifications.map(n => ({ ...n, read: true })));
  };

  return (
    <div className="flex min-h-screen bg-[#F8FAFC]">
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col fixed h-full z-20">
        <div className="p-8 flex items-center gap-3">
          <div className="w-11 h-11 bg-[#1e293b] rounded-xl flex items-center justify-center text-white shadow-lg shadow-slate-200">
            <GraduationCap size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight">EduManager</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Gestión Escolar</p>
          </div>
        </div>

        <nav className="flex-1 px-5 py-2 space-y-1 overflow-y-auto no-scrollbar">
          {menu.map(item => {
            const Icon = item.icon;
            const isTabActive = activeTab === item.id || (item.children && item.children.some(c => c.id === activeTab));
            const isExpanded = expanded === item.id || isTabActive;

            return (
              <div key={item.id} className="space-y-1">
                <button
                  onClick={() => handleTabClick(item.id, !!item.children)}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${
                    isTabActive && !item.children ? 'bg-[#1e293b] text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <Icon size={18} className={isTabActive && !item.children ? 'text-white' : 'text-slate-400'} />
                    <span className="text-sm font-semibold">{item.label}</span>
                  </div>
                  {item.children && (
                    <ChevronDown size={14} className={`transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                  )}
                </button>

                {item.children && isExpanded && (
                  <div className="ml-5 pl-4 border-l border-slate-100 space-y-1 mt-1">
                    {item.children.map(child => (
                      <button
                        key={child.id}
                        onClick={() => setActiveTab(child.id)}
                        className={`w-full text-left px-4 py-2.5 rounded-xl text-xs font-semibold transition-all ${
                          activeTab === child.id ? 'bg-slate-100 text-[#1e293b]' : 'text-slate-400 hover:text-slate-700 hover:bg-slate-50'
                        }`}
                      >
                        {child.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        <div className="p-6 border-t border-slate-50">
          <div className="flex items-center gap-3 p-3.5 rounded-2xl bg-slate-50 border border-slate-100">
            <div className="w-10 h-10 bg-[#1e293b] rounded-full flex items-center justify-center text-white font-bold text-xs">
              {userName?.[0] || 'U'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-bold text-slate-800 truncate">{userName}</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase">{userRole === 'superadmin' ? 'Administrador' : userRole === 'cashier' ? 'Tesorería' : 'Personal'}</p>
            </div>
            <button onClick={onLogout} className="text-slate-400 hover:text-rose-600 transition-colors">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 ml-64 min-h-screen relative">
        <header className="h-20 border-b border-slate-100 bg-white/80 backdrop-blur-md sticky top-0 z-10 px-10 flex items-center justify-between">
          <h2 className="text-lg font-bold text-slate-900 tracking-tight">
            {getHeaderTitle(activeTab)}
          </h2>
          <div className="flex items-center gap-4">
             <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative p-2.5 text-slate-400 hover:bg-slate-50 rounded-xl transition-all border border-slate-100 bg-white"
             >
                <Bell size={20} />
                {unreadCount > 0 && (
                  <span className="absolute top-2 right-2 w-4 h-4 bg-slate-900 text-white text-[9px] font-bold flex items-center justify-center rounded-full border-2 border-white">
                    {unreadCount}
                  </span>
                )}
             </button>
          </div>
        </header>

        {showNotifications && (
          <div className="absolute right-10 top-20 w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-modal">
            <div className="p-5 bg-slate-900 text-white flex justify-between items-center">
              <h3 className="text-xs font-bold uppercase tracking-widest">Notificaciones</h3>
              <button onClick={markAllAsRead} className="text-[10px] font-bold bg-white/10 px-2 py-1 rounded-lg">
                Leído
              </button>
            </div>
            <div className="max-h-96 overflow-y-auto p-2 bg-white">
              {notifications.map(n => (
                <div key={n.id} className={`p-4 rounded-xl mb-1 ${n.read ? 'opacity-40' : 'bg-slate-50 border border-slate-100'}`}>
                  <p className="text-sm font-bold text-slate-900">{n.title}</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">{n.message}</p>
                  <span className="text-[10px] text-slate-400 font-medium block mt-2">{n.date}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="p-10 max-w-6xl mx-auto">{children}</div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  CreditCard, Plus, Search, FileText, CheckCircle2, 
  Clock, AlertCircle, X, Loader2, Save, Printer, 
  Download, Send, Settings, Calendar, DollarSign, ChevronRight,
  MessageCircle, Mail, UserPlus, ChevronDown
} from 'lucide-react';
import { Payment, AcademicLevel, Student } from '../types';
import { INITIAL_STUDENTS, LEVEL_FEES as INITIAL_LEVEL_FEES } from '../constants';
import { supabase } from '../supabaseClient';

const BillingModule: React.FC<{ view: 'fees' | 'config' }> = ({ view }) => {
  const [payments, setPayments] = useState<Payment[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [levelFees, setLevelFees] = useState(INITIAL_LEVEL_FEES);
  const [loading, setLoading] = useState(true);

  // UI States
  const [selectedPayment, setSelectedPayment] = useState<Payment | null>(null);
  const [showReceipt, setShowReceipt] = useState<Payment | null>(null);
  const [showManualFeeModal, setShowManualFeeModal] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showMassGenModal, setShowMassGenModal] = useState(false);
  const [showSendOptions, setShowSendOptions] = useState<Payment | null>(null);

  // Filtering states
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('Todos');

  // Loading states
  const [actionLoading, setActionLoading] = useState(false);

  // Form states
  const [paymentData, setPaymentData] = useState({
    method: 'Efectivo' as any,
    receipt: ''
  });

  const [manualFee, setManualFee] = useState({
    studentId: '',
    concept: 'Cuota Mensual',
    amount: 0,
    dueDate: new Date().toISOString().split('T')[0]
  });

  const [configData, setConfigData] = useState({
    level: '' as any,
    year: '2026',
    monthlyFee: 50000,
    annualEnrollment: 100000,
    dueDay: 10
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    const { data: payData } = await supabase.from('payments').select('*');
    const { data: stData } = await supabase.from('students').select('*');
    setPayments(payData || []);
    setStudents(stData || []);
    setLoading(false);
  };

  // Filter logic
  const filteredPayments = useMemo(() => {
    return payments.filter(p => {
      const student = students.find(s => s.id === p.studentId);
      const studentName = `${student?.firstName} ${student?.lastName}`.toLowerCase();
      const matchesSearch = studentName.includes(searchTerm.toLowerCase()) || 
                           student?.dni.includes(searchTerm) || 
                           p.concept.toLowerCase().includes(searchTerm.toLowerCase());

      const isVencida = !p.isPaid && new Date(p.dueDate) < new Date();
      let matchesStatus = true;
      if (statusFilter === 'Pagadas') matchesStatus = p.isPaid;
      if (statusFilter === 'Pendientes') matchesStatus = !p.isPaid && !isVencida;
      if (statusFilter === 'Vencidas') matchesStatus = isVencida;

      return matchesSearch && matchesStatus;
    });
  }, [payments, searchTerm, statusFilter, students]);

  const handleOpenPay = (p: Payment) => {
    setSelectedPayment(p);
    setPaymentData({ method: 'Efectivo', receipt: `REC-${Math.floor(Math.random() * 100000)}` });
  };

  const processPayment = async () => {
    if (!selectedPayment) return;
    setActionLoading(true);

    const updatedPayment = { 
      ...selectedPayment, 
      isPaid: true, 
      status: 'Pagada' as const, 
      paymentMethod: paymentData.method, 
      receiptNumber: paymentData.receipt, 
      paidAt: new Date().toISOString() 
    };

    await supabase.from('payments').update(updatedPayment).eq('id', selectedPayment.id);

    await fetchData();
    setActionLoading(false);
    setSelectedPayment(null);
    setShowReceipt(updatedPayment);
  };

  const createManualFee = async () => {
    if (!manualFee.studentId || manualFee.amount <= 0) return;
    setActionLoading(true);

    const newFee: any = {
      studentId: manualFee.studentId,
      concept: manualFee.concept,
      amount: manualFee.amount,
      dueDate: manualFee.dueDate,
      status: 'Pendiente',
      isPaid: false,
      school_id: 'school-1'
    };

    await supabase.from('payments').insert(newFee);
    await fetchData();

    setActionLoading(false);
    setShowManualFeeModal(false);
  };

  const runMassGeneration = async () => {
    setActionLoading(true);
    const activeStudents = students.filter(s => s.status === 'ACTIVE');

    const newFees: any[] = activeStudents.map(s => ({
      studentId: s.id,
      concept: 'Cuota Marzo 2026',
      amount: levelFees[s.level] || 0,
      dueDate: '2026-03-10',
      status: 'Pendiente',
      isPaid: false,
      school_id: 'school-1'
    }));

    // Inserción masiva en Supabase (simulada o real)
    await supabase.from('payments').insert(newFees);
    await fetchData();

    setActionLoading(false);
    setShowMassGenModal(false);
    alert(`Se han generado exitosamente ${newFees.length} cuotas para todos los alumnos activos.`);
  };

  const handleEditArancel = (level: AcademicLevel) => {
    setConfigData({
      level,
      year: '2026',
      monthlyFee: levelFees[level],
      annualEnrollment: 100000,
      dueDay: 10
    });
    setShowConfigModal(true);
  };

  const saveConfig = () => {
    if (!configData.level) return;
    setLevelFees({
      ...levelFees,
      [configData.level]: configData.monthlyFee
    });
    setShowConfigModal(false);
  };

  const handleDownload = (p: Payment) => {
    alert(`Iniciando descarga de comprobante ${p.receiptNumber}...`);
  };

  const handleSendAction = (type: 'whatsapp' | 'email') => {
    const method = type === 'whatsapp' ? 'WhatsApp' : 'Email';
    alert(`Comprobante enviado vía ${method} al tutor responsable.`);
    setShowSendOptions(null);
  };

  const ReceiptView = ({ payment, onClose }: { payment: Payment, onClose: () => void }) => {
    const student = students.find(s => s.id === payment.studentId);
