                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Alumno</p>
                <p className="text-base font-bold text-slate-800">{student?.lastName}, {student?.firstName}</p>
                <p className="text-xs text-slate-500">{student?.dni}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">N° Comprobante</p>
