                  >
                    <option>2026</option>
                    <option>2027</option>
                  </select>
                  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                </div>
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-medium text-slate-700">Cuota Mensual <span className="text-rose-500">*</span></label>
              <input 
                type="number"
                value={configData.monthlyFee}
                onChange={e => setConfigData({...configData, monthlyFee: parseInt(e.target.value)})}
