                />
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <button onClick={() => setShowManualFeeModal(false)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-50 transition-all">Cancelar</button>
              <button onClick={createManualFee} className="flex-1 py-3 bg-[#1e293b] text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-all shadow-lg">Crear</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Generación Masiva */}
      {showMassGenModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-sm w-full p-8 animate-modal text-center space-y-6">
            <div className="w-16 h-16 bg-slate-50 text-slate-900 rounded-full flex items-center justify-center mx-auto border border-slate-100">
               <Calendar size={32} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-900 mb-2">Generar Cuotas Masivas</h3>
              <p className="text-sm text-slate-500">Se generarán automáticamente cuotas para los <strong>{students.filter(s => s.status === 'ACTIVE').length} alumnos activos</strong>. Estas aparecerán en el perfil de cada alumno y en el listado general.</p>
            </div>
