              </div>
            </div>

            <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 flex items-center justify-between">
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Abonado</p>
                <p className="text-3xl font-black text-[#1e293b]">$ {payment.amount.toLocaleString()}</p>
              </div>
              <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-emerald-500 shadow-sm border border-slate-100">
                <CheckCircle2 size={24} />
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => handleDownload(payment)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-slate-50 transition-all">
                <Download size={16} /> Descargar
              </button>
              <button onClick={() => setShowSendOptions(payment)} className="flex-1 py-3 bg-[#1e293b] text-white rounded-xl font-bold uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 shadow-lg hover:bg-slate-800 transition-all">
                <Send size={16} /> Enviar
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  if (loading) return (
    <div className="flex items-center justify-center h-64">
      <Loader2 className="animate-spin text-slate-900" size={32} />
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {showReceipt && <ReceiptView payment={showReceipt} onClose={() => setShowReceipt(null)} />}

      {/* Modal Proceso de Cobro */}
      {selectedPayment && !showReceipt && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-md w-full p-8 animate-modal space-y-6 relative">
