            </div>
            <div className="flex gap-3">
               <button onClick={() => setShowMassGenModal(false)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-50">Cancelar</button>
               <button onClick={runMassGeneration} disabled={actionLoading} className="flex-1 py-3 bg-[#1e293b] text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-all shadow-lg flex items-center justify-center gap-2">
                  {actionLoading ? <Loader2 className="animate-spin" size={16} /> : 'Confirmar'}
