                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-slate-800">Carrera *</label>
                    <div className="relative">
                      <select required className="w-full p-3 bg-white border border-slate-200 rounded-lg outline-none appearance-none text-sm focus:border-slate-900 pr-10 font-medium" value={formData.careerId || ''} onChange={e => setFormData({...formData, careerId: e.target.value})}>
                        <option value="">Seleccionar Carrera</option>
                        {careers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>
                  </div>
                </div>
              )}

