              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Referencia Académica</th>
              <th className="px-8 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm font-medium">
            {dataList.map(item => (
              <tr key={item.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-4">
                  <div className="font-bold text-slate-900">
                    {view === 'enrollments' ? getStudentName(item.studentId) : item.name}
                  </div>
                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">
                    {view === 'enrollments' ? `ID: ${item.id.slice(0, 8)}` : item.code}
                  </div>
                </td>
                <td className="px-8 py-4 text-center text-slate-500 font-bold">
                  {view === 'subjects' && <span className="px-3 py-1 bg-slate-100 rounded-lg text-[10px]">{item.grade}</span>}
                  {view === 'careers' && <span className="flex items-center justify-center gap-1.5 text-xs"><Clock size={12} /> {item.duration}</span>}
                  {view === 'enrollments' && <span className="text-slate-800">{getCareerName(item.careerId)}</span>}
                </td>
                <td className="px-8 py-4 text-right space-x-2">
                  <button onClick={() => openEdit(item)} className="p-2 text-slate-400 hover:text-slate-900 transition-all rounded-lg hover:bg-slate-50"><Edit3 size={15} /></button>
                  <button onClick={() => setDeletingId(item.id)} className="p-2 text-rose-300 hover:text-rose-600 transition-all rounded-lg hover:bg-rose-50"><Trash2 size={15} /></button>
                </td>
              </tr>
            ))}
            {dataList.length === 0 && !loading && (
              <tr>
                <td colSpan={3} className="py-20 text-center text-slate-400 font-medium italic">No se encontraron registros.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AcademicModule;

import React, { useState, useEffect, useMemo } from 'react';
import { Book, Plus, Search, Trash2, Edit3, Clock, GraduationCap, X, Loader2, Save, AlertTriangle, ChevronDown, ListFilter } from 'lucide-react';
import { Subject, Career, AcademicLevel } from '../types';
import { INITIAL_STUDENTS } from '../constants';
import { supabase } from '../supabaseClient';

interface AcademicModuleProps {
  view: 'subjects' | 'careers' | 'enrollments';
}

const AcademicModule: React.FC<AcademicModuleProps> = ({ view }) => {
  const [dataList, setDataList] = useState<any[]>([]);
  const [careers, setCareers] = useState<Career[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [btnLoading, setBtnLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterLevel, setFilterLevel] = useState('Todos');

  const [formData, setFormData] = useState<any>({});

  const gradesByLevel: Record<string, string[]> = useMemo(() => ({
    [AcademicLevel.INITIAL]: ['Sala de 3', 'Sala de 4', 'Sala de 5'],
    [AcademicLevel.PRIMARY]: ['1° Grado', '2° Grado', '3° Grado', '4° Grado', '5° Grado', '6° Grado', '7° Grado'],
    [AcademicLevel.SECONDARY]: ['1° Año', '2° Año', '3° Año', '4° Año', '5° Año', '6° Año'],
    [AcademicLevel.TERTIARY]: ['1° Año', '2° Año', '3° Año', '4° Año']
  }), []);

  const tableMap = {
    subjects: 'subjects',
    careers: 'careers',
    enrollments: 'enrollments'
  };

  useEffect(() => {
    fetchData();
    if (view === 'enrollments' || view === 'subjects') fetchCareers();
  }, [view]);

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from(tableMap[view]).select('*');
    setDataList(data || []);
    setLoading(false);
  };

  const fetchCareers = async () => {
    const { data } = await supabase.from('careers').select('*');
    setCareers(data || []);
  };

  const resetForms = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({});
  };

  const openNew = () => {
    if (view === 'subjects') setFormData({ code: '', name: '', level: '', grade: '', hoursPerWeek: 4, prerequisites: [] });
    if (view === 'careers') setFormData({ code: '', name: '', duration: '', description: '', status: 'active' });
    if (view === 'enrollments') setFormData({ studentId: '', careerId: '', year: '2026', status: 'Activa' });
    setIsModalOpen(true);
  };

  const openEdit = (item: any) => {
    setEditingId(item.id);
    setFormData({ ...item });
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    setDeletingId(null);
    try {
      await supabase.from(tableMap[view]).delete().eq('id', id);
      setDataList(prev => prev.filter(i => i.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setBtnLoading(true);
    try {
      if (editingId) {
        await supabase.from(tableMap[view]).update(formData).eq('id', editingId);
      } else {
        const newItem = { ...formData, school_id: 'school-1' };
        await supabase.from(tableMap[view]).insert(newItem);
      }
      await fetchData();
      resetForms();
    } catch (err) {
      console.error(err);
    } finally {
      setBtnLoading(false);
    }
  };

  const filteredData = useMemo(() => {
    return dataList.filter(item => {
      const matchesSearch = (item.name?.toLowerCase() || '').includes(searchTerm.toLowerCase()) || 
                            (item.code?.toLowerCase() || '').includes(searchTerm.toLowerCase());
      const matchesLevel = filterLevel === 'Todos' || item.level === filterLevel;
      return matchesSearch && matchesLevel;
    });
  }, [dataList, searchTerm, filterLevel]);

  const getStudentName = (id: string) => {
    const s = INITIAL_STUDENTS.find(st => st.id === id);
    return s ? `${s.firstName} ${s.lastName}` : 'Alumno Demo';
  };

